import { useMemo, useState } from "react";
import type {
  ModuleEntry,
  SolCatFulfilmentRow,
  FulfilmentPattern,
} from "../lib/stakeholdersData";
import "./FulfilmentMatrix.css";

export interface Props {
  modules: ModuleEntry[];
  rows: SolCatFulfilmentRow[];
}

const ALL = "__all__";

const PATTERN_INFO: Record<
  FulfilmentPattern | "all",
  { label: string; desc?: string }
> = {
  all: { label: "All" },
  healthy: {
    label: "Healthy",
    desc: "Direct ≈ Realistic, both ≥ 50%. Scope and IMDA trace agree.",
  },
  cross_tag_suspect: {
    label: "Cross-tag",
    desc: "Realistic ≥ Direct + 30. IMDA Q likely tagged to another sol cat.",
  },
  over_mapped: {
    label: "Over-mapped",
    desc: "Realistic stays low. Mapping likely too broad.",
  },
  mixed: {
    label: "Mixed",
    desc: "Partial divergence. Inspect gap detail.",
  },
  pending: {
    label: "Pending",
    desc: "Haiku realistic scoring not yet run.",
  },
};

function moduleShort(slug: string, modules: ModuleEntry[]): string {
  const m = modules.find(x => x.slug === slug);
  return m ? (m.short || m.name || slug) : slug;
}

function scoreClass(pct: number): string {
  if (pct >= 80) return "high";
  if (pct >= 50) return "mid";
  if (pct > 0) return "low";
  return "zero";
}

type SortKey =
  | "fulfil_desc"
  | "fulfil_asc"
  | "realistic_desc"
  | "realistic_asc"
  | "delta_desc"
  | "delta_asc"
  | "gap_desc";

function sortRows(rows: SolCatFulfilmentRow[], key: SortKey): SolCatFulfilmentRow[] {
  const copy = rows.slice();
  switch (key) {
    case "fulfil_desc":
      return copy.sort((a, b) => (b.fulfilment_pct || 0) - (a.fulfilment_pct || 0));
    case "fulfil_asc":
      return copy.sort((a, b) => (a.fulfilment_pct || 0) - (b.fulfilment_pct || 0));
    case "realistic_desc":
      return copy.sort((a, b) => (b.realistic_pct ?? -1) - (a.realistic_pct ?? -1));
    case "realistic_asc":
      return copy.sort((a, b) => (a.realistic_pct ?? 999) - (b.realistic_pct ?? 999));
    case "delta_desc":
      return copy.sort((a, b) => (b.delta ?? -999) - (a.delta ?? -999));
    case "delta_asc":
      return copy.sort((a, b) => (a.delta ?? 999) - (b.delta ?? 999));
    case "gap_desc":
      return copy.sort(
        (a, b) =>
          (b.expected_caps - b.fulfilled_caps) - (a.expected_caps - a.fulfilled_caps),
      );
    default:
      return copy;
  }
}

export function FulfilmentMatrix({ modules, rows }: Props) {
  const [moduleFilter, setModuleFilter] = useState<string>(ALL);
  const [sortKey, setSortKey] = useState<SortKey>("fulfil_desc");
  const [patternFilter, setPatternFilter] =
    useState<FulfilmentPattern | "all">("all");
  const [expandedId, setExpandedId] = useState<string | null>(null);

  const hasRealistic = useMemo(
    () => rows.some(r => r.realistic_pct != null),
    [rows],
  );

  const filteredSorted = useMemo(() => {
    let out = rows.slice();
    if (moduleFilter !== ALL) {
      out = out.filter(r => (r.modules || []).includes(moduleFilter));
    }
    if (patternFilter !== "all") {
      out = out.filter(r => (r.pattern || "pending") === patternFilter);
    }
    return sortRows(out, sortKey);
  }, [rows, moduleFilter, sortKey, patternFilter]);

  const summary = useMemo(() => {
    const total = rows.length;
    const high = rows.filter(r => (r.fulfilment_pct || 0) >= 80).length;
    const low = rows.filter(r => (r.fulfilment_pct || 0) < 50).length;
    const zero = rows.filter(r => (r.fulfilment_pct || 0) === 0).length;
    return { total, high, low, zero };
  }, [rows]);

  const patternCounts = useMemo(() => {
    const c: Record<string, number> = { all: rows.length };
    for (const k of Object.keys(PATTERN_INFO)) c[k] ||= 0;
    for (const r of rows) {
      const p = (r.pattern || "pending") as string;
      c[p] = (c[p] || 0) + 1;
    }
    return c;
  }, [rows]);

  return (
    <section className="fm-section">
      <header className="fm-head">
        <h2 className="fm-h2">
          <span className="fm-num">§4</span>
          Sol-cat direct-trace coverage
        </h2>
        <p className="fm-sub">
          For each PSG sol cat, what fraction of caps in its expected scope
          carry a literal IMDA Q-text trace back. <strong>Direct %</strong> is
          the literal trace count; <strong>Realistic %</strong> is Haiku's judgement
          of de-facto product scope ((yes + 0.5×partial) ÷ expected). Click any row
          for cross-trace gap detail.
        </p>
      </header>

      <div className="fm-summary">
        <div className="fm-stat" aria-label="sol cats">
          <div className="fm-stat-num">{summary.total}</div>
          <div className="fm-stat-lbl">sol cats</div>
        </div>
        <div className="fm-stat fm-stat-good" aria-label="≥ 80% fulfilled">
          <div className="fm-stat-num">{summary.high}</div>
          <div className="fm-stat-lbl">≥ 80% fulfilled</div>
        </div>
        <div className="fm-stat fm-stat-warn" aria-label="< 50% fulfilled">
          <div className="fm-stat-num">{summary.low}</div>
          <div className="fm-stat-lbl">&lt; 50% fulfilled</div>
        </div>
        <div className="fm-stat fm-stat-bad" aria-label="no overlap (gap)">
          <div className="fm-stat-num">{summary.zero}</div>
          <div className="fm-stat-lbl">no overlap (gap)</div>
        </div>
      </div>

      {hasRealistic && (
        <div className="fm-pattern-pills">
          <span className="fm-pills-eyebrow">Pattern</span>
          {(Object.keys(PATTERN_INFO) as Array<keyof typeof PATTERN_INFO>).map(key => {
            const info = PATTERN_INFO[key];
            const active = patternFilter === key;
            const count = patternCounts[key] ?? 0;
            return (
              <button
                key={key}
                type="button"
                className={`fm-pill fm-pill-${key}${active ? " active" : ""}`}
                title={info.desc || "All sol cats"}
                aria-label={`${info.label} ${count}`}
                onClick={() => {
                  setPatternFilter(key as FulfilmentPattern | "all");
                  setExpandedId(null);
                }}
              >
                <span className="fm-pill-label">{info.label}</span>
                <span className="fm-pill-count">{count}</span>
              </button>
            );
          })}
        </div>
      )}

      <div className="fm-controls">
        <label htmlFor="fm-mod">Module</label>
        <select id="fm-mod" value={moduleFilter} onChange={e => { setModuleFilter(e.target.value); setExpandedId(null); }}>
          <option value={ALL}>All</option>
          {modules.map(m => (
            <option key={m.slug} value={m.slug}>{m.short || m.name}</option>
          ))}
        </select>

        <label htmlFor="fm-sort">Sort</label>
        <select id="fm-sort" value={sortKey} onChange={e => { setSortKey(e.target.value as SortKey); setExpandedId(null); }}>
          <option value="fulfil_desc">Direct % desc</option>
          <option value="fulfil_asc">Direct % asc</option>
          {hasRealistic && (
            <>
              <option value="realistic_desc">Realistic % desc</option>
              <option value="realistic_asc">Realistic % asc</option>
              <option value="delta_desc">Δ desc (cross-tag suspects first)</option>
              <option value="delta_asc">Δ asc (over-mapped first)</option>
            </>
          )}
          <option value="gap_desc">Largest gap first</option>
        </select>

        <span className="fm-count-note">
          {filteredSorted.length} of {rows.length} sol cats
        </span>
      </div>

      <div className={`fm-table${hasRealistic ? " fm-table-realistic" : ""}`}>
        <div className="fm-row fm-row-head">
          <div>PSG sol cat</div>
          <div className="fm-num">Exp.</div>
          <div className="fm-num">Direct</div>
          <div className="fm-num">Direct %</div>
          {hasRealistic && <div className="fm-num">Realistic %</div>}
          {hasRealistic && <div className="fm-num">Δ</div>}
          {hasRealistic && <div className="fm-num">Pattern</div>}
          <div>Top gap</div>
        </div>

        {filteredSorted.length === 0 ? (
          <div className="fm-empty">No sol cats match the current filters.</div>
        ) : (
          filteredSorted.map(r => {
            const pct = r.fulfilment_pct || 0;
            const isExpanded = expandedId === r.id;
            const gap = r.gaps[0];
            const pattern = r.pattern || "pending";
            const patternInfo = PATTERN_INFO[pattern];
            const deltaTone = (r.delta ?? 0) >= 30 ? "warn-low" : (r.delta ?? 0) <= -30 ? "warn-high" : "";

            return (
              <div key={r.id}>
                <div
                  className={`fm-row fm-row-clickable${isExpanded ? " fm-row-expanded" : ""}`}
                  onClick={() => setExpandedId(isExpanded ? null : r.id)}
                  role="button"
                  tabIndex={0}
                  onKeyDown={e => {
                    if (e.key === "Enter" || e.key === " ") {
                      e.preventDefault();
                      setExpandedId(isExpanded ? null : r.id);
                    }
                  }}
                  title={`${r.display_name || r.id}${r.vertical ? ` · ${r.vertical}` : ""}`}
                >
                  <div className="fm-cell-name">
                    <div className="fm-name-line">
                      <span className="fm-tri" aria-hidden="true">{isExpanded ? "▾" : "▸"}</span>
                      <span className="fm-name-text">{r.display_name || r.id}</span>
                    </div>
                    <div className="fm-meta-line">
                      {r.vertical || ""}
                      {r.modules.length > 0 ? ` · ${r.modules.map(m => moduleShort(m, modules)).join(", ")}` : ""}
                    </div>
                  </div>
                  <div className="fm-num">{r.expected_caps}</div>
                  <div className="fm-num">{r.fulfilled_caps}</div>
                  <div className="fm-num">
                    <span className={`fm-score fm-score-${scoreClass(pct)}`}>{pct}%</span>
                  </div>
                  {hasRealistic && (
                    <div className="fm-num">
                      {r.realistic_pct != null ? (
                        <span
                          className={`fm-score fm-score-${scoreClass(r.realistic_pct)}`}
                          title={`${r.realistic_yes ?? 0} yes · ${r.realistic_partial ?? 0} partial · ${r.realistic_no ?? 0} no out of ${r.expected_caps} expected`}
                        >
                          {r.realistic_pct}%
                        </span>
                      ) : (
                        <span className="fm-score fm-score-zero">—</span>
                      )}
                    </div>
                  )}
                  {hasRealistic && (
                    <div className={`fm-num fm-delta ${deltaTone}`}>
                      {r.delta != null ? `${r.delta > 0 ? "+" : ""}${r.delta}` : "—"}
                    </div>
                  )}
                  {hasRealistic && (
                    <div className="fm-num">
                      <span className={`fm-pattern-badge fm-pattern-${pattern}`} title={patternInfo.desc || ""}>
                        {patternInfo.label}
                      </span>
                    </div>
                  )}
                  <div className="fm-cell-gap">
                    {gap ? (gap.cap_name || gap.cap_id) : <span className="muted italic">none</span>}
                  </div>
                </div>

                {isExpanded && (
                  <div className="fm-gap-detail">
                    {(r.gaps || []).length === 0 ? (
                      <div className="fm-gap-empty">
                        All expected caps trace directly. Real-world fulfilment likely matches.
                      </div>
                    ) : (
                      <>
                        <div className="fm-gap-eyebrow">
                          Gap caps (this sol cat is in their scope but didn't trace; here's where they actually trace)
                        </div>
                        {r.gaps.map(g => (
                          <div key={g.cap_id} className="fm-gap-item">
                            <div className="fm-gap-cap">
                              <div className="fm-gap-cap-name">{g.cap_name || g.cap_id}</div>
                              <div className="fm-gap-cap-id">{g.cap_id}</div>
                            </div>
                            <div className="fm-gap-traces">
                              <div className="fm-gap-traces-label">Trace points to:</div>
                              {g.traces_to.length === 0 ? (
                                <span className="muted italic">no IMDA trace anywhere</span>
                              ) : (
                                g.traces_to.map(t => (
                                  <span key={t.id} className="fm-trace-chip" title={t.id}>
                                    {t.display_name || t.id}
                                  </span>
                                ))
                              )}
                            </div>
                          </div>
                        ))}
                      </>
                    )}
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>
    </section>
  );
}
