import type { PipelineStage, AuditSummary } from "../lib/stakeholdersData";
import "./PipelineDeepDive.css";

export interface Props {
  stages: PipelineStage[];
  audit: AuditSummary;
}

type Tone = "good" | "warn" | "bad";

interface AuditCard {
  label: string;
  value: number | null | undefined;
  tone: Tone;
}

function p0Tone(v: number | null | undefined): Tone {
  if (v == null) return "warn";
  return v === 0 ? "good" : "bad";
}

export function PipelineDeepDive({ stages, audit }: Props) {
  const cards: AuditCard[] = [
    { label: "Solcat-join P0 violations", value: audit.solcat_p0 ?? null, tone: p0Tone(audit.solcat_p0) },
    { label: "Solcat-join P1 warnings", value: audit.solcat_p1 ?? null, tone: "warn" },
    { label: "Checklist-format P0 violations", value: audit.checklist_p0 ?? null, tone: p0Tone(audit.checklist_p0) },
    { label: "UC pipeline P0 violations", value: audit.uc_p0 ?? null, tone: p0Tone(audit.uc_p0) },
  ];

  return (
    <section className="pdd-section">
      <header className="pdd-head">
        <h2 className="pdd-h2">
          <span className="pdd-num">§6</span>
          Pipeline deep-dive
        </h2>
        <p className="pdd-sub">
          Full stage list with the data-science analogue of each step — useful for
          engineers reviewing the trust chain or replicating the pipeline.
        </p>
      </header>

      <table className="pdd-stage-table">
        <thead>
          <tr>
            <th className="pdd-col-num">#</th>
            <th>Stage</th>
            <th>DS / ML analogue</th>
            <th>What it does (plain)</th>
            <th>Stat</th>
          </tr>
        </thead>
        <tbody>
          {stages.map((s, i) => (
            <tr key={s.name} className="pdd-stage-row">
              <td className="pdd-col-num pdd-stage-step">{i + 1}</td>
              <td className="pdd-stage-name">{s.name}</td>
              <td className="pdd-stage-ds">{s.ds_analogue}</td>
              <td className="pdd-stage-desc">{s.plain_description}</td>
              <td className="pdd-stage-stat">{s.stat || ""}</td>
            </tr>
          ))}
        </tbody>
      </table>

      <h3 className="pdd-h3">Audit gates</h3>
      <div className="pdd-audit-grid">
        {cards.map(c => (
          <div key={c.label} className={`pdd-audit-card pdd-tone-${c.tone}`}>
            <div className="pdd-audit-value">{c.value == null ? "—" : c.value}</div>
            <div className="pdd-audit-label">{c.label}</div>
          </div>
        ))}
      </div>
      <p className="pdd-foot">
        Audits are run after every pipeline change; P0 violations block CI. See{" "}
        <code>scripts/audit_*</code> for rule definitions.
      </p>
    </section>
  );
}
