import type { ChecklistFormat } from "../lib/checklistFormat";
import "./ChecklistFormatTabs.css";

const TABS: Array<{ key: ChecklistFormat; label: string; hint: string }> = [
  { key: "type1_1", label: "Type 1.1 (rows)", hint: "Original IMDA Type 1.1 — one row per cap with terse 1-liner" },
  { key: "type2", label: "Type 2 (lumped)", hint: "IMDA Type 2 — single umbrella per tier with sub-bullets" },
  { key: "pending_edits", label: "Pending edits", hint: "Now vs Draft — caps with unpublished drafts, field-by-field" },
  { key: "change_log", label: "Change log", hint: "Live audit trail from /api/audit (saves, clears, publishes)" },
];

export interface Props {
  format: ChecklistFormat;
  onChange: (next: ChecklistFormat) => void;
  /**
   * Per-tab badge counts. Today only "pending_edits" is decorated, but the
   * shape is open so future tabs (e.g. "change_log" with new-since-last-visit)
   * can opt in.
   */
  badges?: Partial<Record<ChecklistFormat, number>>;
}

export function ChecklistFormatTabs({ format, onChange, badges }: Props) {
  return (
    <div className="cl-fmt-tabs" role="tablist" aria-label="Checklist format">
      {TABS.map(t => {
        const active = t.key === format;
        const badge = badges?.[t.key];
        return (
          <button
            key={t.key}
            type="button"
            role="tab"
            aria-selected={active}
            className={`cl-fmt-tab${active ? " active" : ""}`}
            title={t.hint}
            onClick={() => {
              if (!active) onChange(t.key);
            }}
          >
            {t.label}
            {badge !== undefined && badge > 0 && (
              <span className="cl-fmt-tab-badge" aria-label={`${badge} pending`}>
                {badge}
              </span>
            )}
          </button>
        );
      })}
    </div>
  );
}
