import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { loadCanonicalModule } from "../lib/canonicalLoader";
import { api, type Me } from "../lib/api";
import {
  type CanonicalModule,
  type Capability,
  partitionCaps,
  buildClusters,
} from "../types/canonical";
import { useDrafts } from "../contexts/DraftsContext";
import { ModuleStateProvider, useModuleState } from "../contexts/ModuleStateContext";
import { Type2Umbrella } from "../components/Type2Umbrella";
import { Type11Table } from "../components/Type11Table";
import { ChangeLogTable } from "../components/ChangeLogTable";
import { ChecklistFormatTabs } from "../components/ChecklistFormatTabs";
import { PendingEditsView } from "../components/PendingEditsView";
import { SectorFilter } from "../components/SectorFilter";
import { AiFeaturesUmbrella } from "../components/AiFeaturesUmbrella";
import { QuickEditPane } from "../components/QuickEditPane";
import {
  GENERIC,
  filterCapsBySector,
  type SectorFilter as SectorFilterValue,
} from "../lib/sectorFilter";
import { type ChecklistFormat } from "../lib/checklistFormat";
import {
  loadAiFeatures,
  type AiFeatureExample,
} from "../lib/aiFeatures";
import "./CanonicalPage.css";

const KNOWN_MODULES = new Set([
  "financial_management",
  "sales_and_crm",
  "supply_chain_and_inventory",
  "human_resources_management",
  "manufacturing_management",
  "asset_management",
  "field_service_management",
  "fleet_management",
  "project_management",
  "others",
]);

export function CanonicalPage() {
  const { module } = useParams<{ module: string }>();
  // The body needs ModuleStateProvider — wrap inline so the provider's
  // moduleSlug always matches the URL param.
  return (
    <ModuleStateProvider moduleSlug={module || ""}>
      <CanonicalPageBody />
    </ModuleStateProvider>
  );
}

function CanonicalPageBody() {
  const { module } = useParams<{ module: string }>();
  const [data, setData] = useState<CanonicalModule | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [me, setMe] = useState<Me | null>(null);
  const [sector, setSector] = useState<SectorFilterValue>(GENERIC);
  const [format, setFormat] = useState<ChecklistFormat>("type2");
  const [quickEdit, setQuickEdit] = useState<boolean>(false);
  const [aiUmbrellaQuestion, setAiUmbrellaQuestion] = useState<string>("");
  const [aiExamples, setAiExamples] = useState<AiFeatureExample[]>([]);
  const { aiFeaturesResponse, setAiFeaturesResponse } = useModuleState();
  const { getDraftFields, draftsByCap } = useDrafts();

  // Pull the static ai_features.json once (cached) and pick the per-module
  // example list. Reviewer response state lives in ModuleStateContext —
  // hydrated from D1, audit-logged on every change.
  useEffect(() => {
    if (!module) return;
    loadAiFeatures()
      .then(payload => {
        setAiUmbrellaQuestion(payload.umbrella_question);
        setAiExamples(payload.modules[module]?.examples || []);
      })
      .catch(() => {
        setAiUmbrellaQuestion("");
        setAiExamples([]);
      });
  }, [module]);

  useEffect(() => {
    setData(null);
    setError(null);
    if (!module) return;
    if (!KNOWN_MODULES.has(module)) {
      setError(`Unknown module: ${module}`);
      return;
    }
    loadCanonicalModule(module)
      .then(setData)
      .catch(e => setError(String(e?.message || e)));
  }, [module]);

  useEffect(() => {
    api.me().then(setMe).catch(() => {});
  }, []);

  if (error) return <div className="canonical-page error">Error: {error}</div>;
  if (!data) return <div className="canonical-page muted">Loading {module}…</div>;

  // Apply draft overlays to canonical caps so EVERY editable field shows
  // its draft value in the preview before publish. Mirrors the worker's
  // ALLOWED_FIELDS whitelist (src/index.js): name, description, sme_tier,
  // in_checklist, vendor_question, vendor_question_terse, note.
  const withDraftOverlay: Capability[] = (data.capabilities || []).map(c => {
    if (!module) return c;
    const draft = getDraftFields(module, c.id);
    if (!draft) return c;
    const baseVq = c.vendor_questions || {};
    const nextVq =
      draft.vendor_question !== undefined || draft.vendor_question_terse !== undefined
        ? {
            ...baseVq,
            ...(draft.vendor_question !== undefined ? { question: draft.vendor_question } : {}),
            ...(draft.vendor_question_terse !== undefined
              ? { question_terse: draft.vendor_question_terse }
              : {}),
          }
        : baseVq;
    return {
      ...c,
      sme_tier: draft.sme_tier !== undefined ? draft.sme_tier : c.sme_tier,
      in_checklist: draft.in_checklist !== undefined ? draft.in_checklist : c.in_checklist,
      name: draft.name !== undefined ? draft.name : c.name,
      description: draft.description !== undefined ? draft.description : c.description,
      vendor_questions: nextVq,
    };
  });

  const applicableSectors = deriveApplicableSectors(withDraftOverlay);
  const filtered = filterCapsBySector(withDraftOverlay, sector);
  const partitioned = partitionCaps(filtered);
  const moduleId = data.module_id || "";
  const requiredClusters = buildClusters(
    partitioned.required,
    data.preferred_clusters?.required,
    `Core ${shortName(data.module_name || module || "")} module features`,
  );
  const preferredClusters = buildClusters(
    partitioned.preferred,
    data.preferred_clusters?.preferred,
    `Preferred ${shortName(data.module_name || module || "")} features`,
  );

  return (
    <div className="canonical-page">
      <header className="page-header">
        <span className="page-eyebrow">PSG ERP Spec · {moduleId}</span>
        <h1>{data.module_name}</h1>
        <p className="page-headline">
          {data.module_headline || data.module_description || ""}
        </p>
        <div className="page-counts">
          <Stat n={data.capabilities?.length || 0} label="capabilities" />
          <Stat n={partitioned.required.length} label="required" />
          <Stat n={partitioned.preferred.length} label="preferred" />
          <Stat n={partitioned.advanced.length} label="advanced" />
          <Stat n={partitioned.optional.length} label="optional" />
        </div>
        <SectorFilter
          sector={sector}
          applicableSectors={applicableSectors}
          onChange={setSector}
        />
        <div className="page-header-row">
          <ChecklistFormatTabs
            format={format}
            onChange={setFormat}
            badges={{
              pending_edits: countPendingForModule(draftsByCap, module || ""),
            }}
          />
          {format !== "change_log" && format !== "pending_edits" && (
            <button
              type="button"
              className={`quickedit-toggle${quickEdit ? " active" : ""}`}
              aria-pressed={quickEdit}
              onClick={() => setQuickEdit(v => !v)}
              title={quickEdit
                ? "Exit Quick Edit and return to single-pane preview"
                : "Open the bulk-edit pane on the right side"}
            >
              {quickEdit ? "Exit Quick Edit" : "Quick Edit"}
            </button>
          )}
        </div>
      </header>

      <div className={`canonical-body${quickEdit && format !== "change_log" && format !== "pending_edits" ? " qe-split" : ""}`}>
        <div className="qe-left">

      {format === "change_log" ? (
        <section className="page-section">
          <h2 className="section-heading">Change log</h2>
          <p className="muted small">
            Live edit trail from <code>/api/audit</code> — saves, clears, and
            publishes recorded against this module. Each row shows the old →
            new diff per field (rows from before today's prior-field schema
            land carry "prior not captured").
          </p>
          <ChangeLogTable module={module || ""} />
        </section>
      ) : format === "pending_edits" ? (
        <section className="page-section">
          <h2 className="section-heading">Pending edits — Now vs Draft</h2>
          <p className="muted small">
            Per-cap diff showing what's <strong>currently published</strong> in
            canonical vs what the unpublished draft will change it to. Hit
            <strong> Publish</strong> in the bottom-right to commit them all.
          </p>
          <PendingEditsView
            module={module || ""}
            caps={data.capabilities || []}
          />
        </section>
      ) : format === "type1_1" ? (
        <section className="page-section">
          <h2 className="section-heading">Vendor Self-Assessment Checklist · Type 1.1</h2>
          <p className="muted small">
            One row per cap, grouped by sub-module specialty within each family
            (matches the IMDA Type 1.1 deliverable shape). Tier mixed within
            each sub-module (Required first, then Preferred, then Advanced).
            Caps without a sub-module land under Other / Unassigned.
          </p>
          <Type11Table
            moduleId={moduleId}
            caps={[
              ...partitioned.required,
              ...partitioned.preferred,
              ...partitioned.advanced,
            ]}
            subModules={data.sub_modules}
          />
        </section>
      ) : (
        <>
          <section className="page-section">
            <h2 className="section-heading">Mandatory umbrellas</h2>
            {requiredClusters.map((cl, idx) => (
              <Type2Umbrella
                key={cl.id}
                moduleId={moduleId}
                moduleSlug={module || ""}
                umbrellaKey={`required:${cl.id}`}
                seq={String(idx + 1).padStart(2, "0")}
                title={cl.name}
                tierLabel="Mandatory"
                tierClass="mandatory"
                caps={cl.caps}
                multiSelect={false}
                signedInEmail={me?.email}
              />
            ))}
          </section>

          <section className="page-section">
            <h2 className="section-heading">Preferred umbrellas</h2>
            {preferredClusters.map((cl, idx) => (
              <Type2Umbrella
                key={cl.id}
                moduleId={moduleId}
                moduleSlug={module || ""}
                umbrellaKey={`preferred:${cl.id}`}
                seq={String(requiredClusters.length + idx + 1).padStart(2, "0")}
                title={cl.name}
                tierLabel="Preferred (multi-select)"
                tierClass="preferred"
                caps={cl.caps}
                multiSelect
                signedInEmail={me?.email}
              />
            ))}
          </section>

          {partitioned.advanced.length > 0 && (
            <section className="page-section">
              <h2 className="section-heading">Advanced</h2>
              <Type2Umbrella
                moduleId={moduleId}
                moduleSlug={module || ""}
                umbrellaKey="advanced:all"
                seq="A"
                title="Advanced / Enterprise features"
                tierLabel="Advanced (multi-select)"
                tierClass="advanced"
                caps={partitioned.advanced}
                multiSelect
                signedInEmail={me?.email}
              />
            </section>
          )}
        </>
      )}

      {format !== "change_log" && format !== "pending_edits" && aiUmbrellaQuestion && (
        <section className="page-section">
          <h2 className="section-heading">AI Features</h2>
          <p className="muted small">
            Mandatory to provide a response · changes audit-logged in the
            Change log tab.
          </p>
          <AiFeaturesUmbrella
            umbrellaQuestion={aiUmbrellaQuestion}
            examples={aiExamples}
            response={aiFeaturesResponse}
            onChange={setAiFeaturesResponse}
          />
        </section>
      )}

      {format !== "change_log" && format !== "pending_edits" && partitioned.optional.length > 0 && (
        <section className="page-section">
          <h2 className="section-heading">Optional / Add-ons</h2>
          <p className="muted small">
            Caps flagged <code>in_checklist: false</code> — listed for reference
            but not gated for verdict.
          </p>
          <ol className="optional-list">
            {partitioned.optional.map((c: Capability) => (
              <li key={c.id}>
                <strong>{c.name}</strong>{" "}
                <span className="muted small">[{c.sme_tier || "—"}]</span>
              </li>
            ))}
          </ol>
        </section>
      )}

        </div>
        {quickEdit && format !== "change_log" && format !== "pending_edits" && (
          <aside className="qe-right">
            <QuickEditPane
              module={module || ""}
              caps={[
                ...partitioned.required,
                ...partitioned.preferred,
                ...partitioned.advanced,
              ]}
              signedInEmail={me?.email}
            />
          </aside>
        )}
      </div>

      <footer className="page-footer muted small">
        Read-only React preview · Phase 3 of the SPA migration · for full editor
        functionality use the legacy viewer at{" "}
        <code>/canonical_{module}.html</code>.
      </footer>
    </div>
  );
}

function Stat({ n, label }: { n: number; label: string }) {
  return (
    <div className="stat">
      <div className="stat-n">{n}</div>
      <div className="stat-label">{label}</div>
    </div>
  );
}

function shortName(name: string): string {
  return name.toLowerCase()
    .replace(" management", "")
    .replace(" & ", " ")
    .trim();
}

// Derive the L1-applicable sector list from caps' sector_relevance.scope_sectors.
// Step 7b stamps every cap with the same module-scoped list, so a union is safe
// (and resilient to caps that pre-date 7b, which simply contribute nothing).
function countPendingForModule(
  draftsByCap: Map<string, { module: string }>,
  module: string,
): number {
  if (!module) return 0;
  let count = 0;
  draftsByCap.forEach(d => { if (d.module === module) count += 1; });
  return count;
}

function deriveApplicableSectors(caps: Capability[]): string[] {
  const out = new Set<string>();
  for (const c of caps) {
    const scope = c.sector_relevance?.scope_sectors;
    if (Array.isArray(scope)) scope.forEach(s => out.add(s));
  }
  return Array.from(out);
}
