import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from "react";
import { api, type Draft, type DraftFields } from "../lib/api";

/**
 * Centralised draft state for the SPA.
 *
 * Reads:
 *   - draftsByCap: Map<"<module>:<cap_id>", Draft>  — server state cached here
 *   - getDraftFields(module, capId): the resolved draft fields, regardless of
 *     whether the source is local pending or cloud
 *
 * Writes:
 *   - saveDraft(): debounced PUT /api/drafts; updates local cache optimistically
 *   - clearDraft(): DELETE /api/drafts; removes from cache
 *
 * No localStorage here — Phase 4 keeps it simple. Phase 5 may add an offline
 * fallback layer if reviewers complain about Worker hiccups losing in-flight
 * drafts.
 */

interface DraftsContextValue {
  draftsByCap: Map<string, Draft>;
  loading: boolean;
  error: string | null;
  refresh: () => Promise<void>;
  getDraft: (module: string, capId: string) => Draft | undefined;
  getDraftFields: (module: string, capId: string) => DraftFields | undefined;
  saveDraft: (module: string, capId: string, fields: DraftFields) => Promise<void>;
  clearDraft: (module: string, capId: string) => Promise<void>;
  publish: () => Promise<{ ok: boolean; applied: number; commit_url?: string; message?: string }>;
}

const DraftsContext = createContext<DraftsContextValue | null>(null);

function key(module: string, capId: string) {
  return `${module}:${capId}`;
}

export function DraftsProvider({ children }: { children: ReactNode }) {
  const [draftsByCap, setDraftsByCap] = useState<Map<string, Draft>>(new Map());
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const refresh = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const drafts = await api.listDrafts();
      const next = new Map<string, Draft>();
      for (const d of drafts) next.set(key(d.module, d.cap_id), d);
      setDraftsByCap(next);
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : String(e);
      setError(msg);
      console.warn("[drafts] refresh failed:", msg);
    } finally {
      setLoading(false);
    }
  }, []);

  // Initial load + on focus refresh
  useEffect(() => {
    refresh();
    const onFocus = () => { refresh(); };
    window.addEventListener("focus", onFocus);
    return () => window.removeEventListener("focus", onFocus);
  }, [refresh]);

  const getDraft = useCallback(
    (module: string, capId: string) => draftsByCap.get(key(module, capId)),
    [draftsByCap],
  );

  const getDraftFields = useCallback(
    (module: string, capId: string) => draftsByCap.get(key(module, capId))?.fields,
    [draftsByCap],
  );

  const saveDraft = useCallback(async (module: string, capId: string, fields: DraftFields) => {
    if (!fields || Object.keys(fields).length === 0) return;
    // Optimistic update — UI reflects the change immediately; if the API call
    // fails we re-fetch authoritative state from the server.
    setDraftsByCap(prev => {
      const next = new Map(prev);
      const existing = next.get(key(module, capId));
      next.set(key(module, capId), {
        module, cap_id: capId, fields,
        author: existing?.author || { email: "(you)" },
        updated_at: new Date().toISOString(),
      });
      return next;
    });
    try {
      const saved = await api.saveDraft(module, capId, fields);
      setDraftsByCap(prev => {
        const next = new Map(prev);
        next.set(key(module, capId), saved);
        return next;
      });
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : String(e);
      console.warn("[drafts] save failed, refetching:", msg);
      await refresh();
      throw e;
    }
  }, [refresh]);

  const clearDraft = useCallback(async (module: string, capId: string) => {
    setDraftsByCap(prev => {
      const next = new Map(prev);
      next.delete(key(module, capId));
      return next;
    });
    try {
      await api.clearDraft(module, capId);
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : String(e);
      console.warn("[drafts] clear failed, refetching:", msg);
      await refresh();
      throw e;
    }
  }, [refresh]);

  const publish = useCallback(async () => {
    const result = await api.publish();
    if (result.ok) {
      // Worker drained drafts on its side — refresh local cache.
      setDraftsByCap(new Map());
      // Soft refetch in case there were races with other reviewers' new edits.
      setTimeout(() => { refresh(); }, 1500);
    }
    return result;
  }, [refresh]);

  const value = useMemo<DraftsContextValue>(() => ({
    draftsByCap,
    loading,
    error,
    refresh,
    getDraft,
    getDraftFields,
    saveDraft,
    clearDraft,
    publish,
  }), [draftsByCap, loading, error, refresh, getDraft, getDraftFields, saveDraft, clearDraft, publish]);

  return <DraftsContext.Provider value={value}>{children}</DraftsContext.Provider>;
}

export function useDrafts() {
  const ctx = useContext(DraftsContext);
  if (!ctx) throw new Error("useDrafts must be inside DraftsProvider");
  return ctx;
}
