/**
 * Static data backing the SPA Stakeholders page. Built by
 * scripts/build_stakeholders_summary.py from canonical JSONs +
 * sol-cat join + audit outputs. Re-run after pipeline changes.
 *
 * Schema is additive — sections will extend this payload as they
 * port from the legacy /stakeholders.html viewer (§2 coverage map,
 * §3 evidence drill, etc.).
 */

export interface StakeholdersKPIs {
  sol_cats: number;
  sol_cats_excluded: number;
  raw_requirements: number;
  unique_caps: number;
  modules: number;
  proxy_erps: number;
  psg_solutions: number;
}

export interface PipelineStage {
  name: string;
  ds_analogue: string;
  plain_description: string;
  stat: string;
}

export interface AuditSummary {
  solcat_p0?: number | null;
  solcat_p1?: number | null;
  checklist_p0?: number | null;
  uc_p0?: number | null;
}

export interface ModuleEntry {
  slug: string;
  name: string;
  short: string;
}

export type SubModuleVerdict =
  | "truly_generic"
  | "mostly_generic"
  | "mixed"
  | "industry_specific";

export interface SubModuleChip {
  id: string;
  canonical_name: string;
  module: string;
  family: string;
  baseline?: boolean;
  verdict?: SubModuleVerdict;
  pct_generic?: number | null;
  avg_relevance_pct?: number | null;
}

export interface SolCatWarning {
  rule: string;
  msg?: string;
}

export interface SolCatRow {
  id: string;
  display_name: string;
  vertical: string;
  modules: string[];
  imda_req_count: number;
  sub_modules: SubModuleChip[];
  warnings: SolCatWarning[];
  vertical_saas?: boolean;
  vertical_saas_industry?: string | null;
}

export interface ExcludedSolCat {
  id: string;
  display_name?: string;
  vertical?: string;
  excluded_group?: string;
  excluded_reason?: string;
}

export interface SubModuleSpecificity {
  verdict: SubModuleVerdict;
  generic_caps?: number;
  total_caps?: number;
  pct_generic?: number;
  avg_relevance_pct?: number;
}

// §3 evidence-drill types ─────────────────────────────────────────────

export interface ImdaRef {
  q_title: string;
  sources: string[]; // sol-cat ids
}

export interface SectorEntry {
  relevant: boolean;
  reason?: string;
}

export interface CapSectorRelevance {
  generic?: boolean;
  scope_sectors?: string[];
  sectors?: Record<string, SectorEntry>;
}

export interface CapEvidence {
  id: string;
  name: string;
  module: string;
  family?: string | null;
  sme_tier?: string;
  question?: string;
  imda_refs: ImdaRef[];
  vendor_citations: string[];
  sector_relevance?: CapSectorRelevance;
  sub_module_id?: string | null;
  sub_module_name?: string | null;
  sub_module_description?: string | null;
}

export interface ModuleImdaQuestion {
  sol_cat: string;
  sol_cat_short: string;
  q_title: string;
  caps: Array<{ id: string; name: string }>;
}

export interface ModuleImdaSummary {
  total_caps: number;
  imda_driven_count: number;
  proxy_only_count: number;
  top_solcats: Array<{ sol_cat: string; sol_cat_short: string; cap_count: number }>;
}

// §4 fulfilment-matrix types ──────────────────────────────────────────

export type FulfilmentPattern =
  | "healthy"
  | "cross_tag_suspect"
  | "over_mapped"
  | "mixed"
  | "pending";

export interface FulfilmentGap {
  cap_id: string;
  cap_name?: string;
  traces_to: Array<{ id: string; display_name?: string }>;
}

export interface SolCatFulfilmentRow {
  id: string;
  display_name?: string;
  vertical?: string;
  modules: string[];
  expected_caps: number;
  fulfilled_caps: number;
  fulfilment_pct: number;            // direct-trace %
  gaps: FulfilmentGap[];
  // T4-b realistic Haiku fields — null until scored.
  realistic_pct?: number | null;
  realistic_yes?: number;
  realistic_partial?: number;
  realistic_no?: number;
  delta?: number | null;
  pattern?: FulfilmentPattern;
}

export interface FulfilmentMeta {
  last_updated?: string;
}

// §5 reference-ERP scoreboard ─────────────────────────────────────────

export type ProxyFulfilment = "yes" | "partial" | "no";

export interface ProxyScore {
  fulfils: ProxyFulfilment;
  reason?: string;
  scored_at?: string;
}

export interface ProxyFulfilmentPayload {
  _meta?: { last_updated?: string; generated_by?: string; model?: string; phase?: string };
  caps?: Record<string, Record<string, ProxyScore>>;
}

// Per-module deep-dive (§Per-module) ──────────────────────────────────

export interface BuildChainSolCat {
  id: string;
  display_name: string;
  vertical?: string;
  vertical_saas?: boolean;
  cap_count: number;
}

export interface BuildChainProxy {
  id: string;
  cap_count: number;
}

export interface BuildChain {
  imda_driven_count: number;
  proxy_only_count: number;
  total_caps: number;
  top_solcats: BuildChainSolCat[];
  top_proxies: BuildChainProxy[];
  narrative?: string;
}

export interface PmCapEvidence {
  id: string;
  name: string;
  module: string;
  family?: string | null;
  sme_tier?: string;
  sub_module_id?: string | null;
  sub_module_name?: string | null;
  question?: string;
}

export interface SubModuleToSolCats {
  id: string;
  canonical_name: string;
  family: string;
  verdict?: SubModuleVerdict;
  pct_generic?: number;
  cap_count: number;
  backing_solcats: Array<{ id: string; display_name: string; vertical?: string }>;
  tier_mix?: { r: number; p: number; a: number };
}

export type CellLabel = "covers" | "no" | "no_required" | "n/a" | string;

export interface OnboardingMatrixCell {
  sm_id: string;
  sm_name: string;
  family?: string;
  label: CellLabel;
  pct: number;
  yes: number;
  partial: number;
  no: number;
  total: number;
  r_yes: number;
  r_partial: number;
  r_no: number;
  r_total: number;
  p_yes: number;
  p_partial: number;
  p_no: number;
  p_total: number;
  a_yes: number;
  a_partial: number;
  a_no: number;
  a_total: number;
  not_covered_caps?: Array<{ name: string; status: string }>;
}

export interface OnboardingMatrixRow {
  id: string;
  display_name: string;
  vertical?: string;
  vertical_saas?: boolean;
  primary_module?: string;
  primary_modules?: string[];
  is_primary: boolean;
  sub_modules: Record<string, OnboardingMatrixCell>;
}

export interface ReEvalFlag {
  kind: string;
  severity?: "high" | "med" | "low" | "info";
  msg: string;
  data?: unknown;
}

export interface PerModuleTierData {
  sub_module_to_solcats: SubModuleToSolCats[];
  onboarding_matrix: OnboardingMatrixRow[];
  flags?: ReEvalFlag[];
  caps_in_tier: number;
}

export interface PerModuleView {
  build_chain: BuildChain;
  cap_evidence: PmCapEvidence[];
  tiers: {
    required?: PerModuleTierData;
    required_preferred?: PerModuleTierData;
    all?: PerModuleTierData;
  };
  reeval_flags?: ReEvalFlag[];
}

export interface StakeholdersSummary {
  generated_at: string;
  kpis: StakeholdersKPIs;
  modules: ModuleEntry[];
  pipeline_stages: PipelineStage[];
  audit_summary: AuditSummary;
  sol_cats: SolCatRow[];
  excluded_sol_cats: ExcludedSolCat[];
  exclusion_groups: Record<string, string>;
  submodule_specificity: Record<string, SubModuleSpecificity>;
  caps_index: CapEvidence[];
  module_imda_questions: Record<string, ModuleImdaQuestion[]>;
  module_imda_summary: Record<string, ModuleImdaSummary>;
  proxy_id_to_name: Record<string, string>;
  solcat_fulfilment: SolCatFulfilmentRow[];
  solcat_fulfilment_realistic_meta: FulfilmentMeta;
  proxy_fulfilment: ProxyFulfilmentPayload;
  per_module_views: Record<string, PerModuleView>;
  // Trailing index signature kept for forward compatibility with payload
  // fields the SPA hasn't typed yet.
  [key: string]: unknown;
}

let _cache: StakeholdersSummary | null = null;
let _inflight: Promise<StakeholdersSummary> | null = null;

export async function loadStakeholdersSummary(): Promise<StakeholdersSummary> {
  if (_cache) return _cache;
  if (_inflight) return _inflight;
  _inflight = fetch("/stakeholders_summary.json", { credentials: "same-origin" })
    .then(res => {
      if (!res.ok) throw new Error(`stakeholders_summary fetch failed: ${res.status}`);
      return res.json() as Promise<StakeholdersSummary>;
    })
    .then(payload => {
      _cache = payload;
      _inflight = null;
      return payload;
    })
    .catch(e => {
      _inflight = null;
      throw e;
    });
  return _inflight;
}

export function _resetStakeholdersSummaryCache(): void {
  _cache = null;
  _inflight = null;
}
