import { Link } from "react-router-dom";
import type { ModuleSummary } from "../lib/dashboardSummary";
import "./DashboardTile.css";

export interface Props {
  slug: string;
  summary: ModuleSummary;
  draftCount: number;
}

function StatBlock({ label, value }: { label: string; value: number }) {
  return (
    <div className="dt-stat" aria-label={label}>
      <div className="dt-stat-value">{value}</div>
      <div className="dt-stat-label">{label}</div>
    </div>
  );
}

export function DashboardTile({ slug, summary, draftCount }: Props) {
  return (
    <article className="dt-tile">
      <header className="dt-head">
        <Link to={`/canonical/${slug}`} className="dt-name">
          <h3>{summary.name}</h3>
        </Link>
        <code className="dt-slug">{slug}</code>
        {draftCount > 0 && (
          <span className="dt-draft-pill" title={`${draftCount} unpublished drafts on this module`}>
            {draftCount} drafts
          </span>
        )}
      </header>

      <div className="dt-stats dt-stats-tiers">
        <StatBlock label="Required" value={summary.required} />
        <StatBlock label="Preferred" value={summary.preferred} />
        <StatBlock label="Advanced" value={summary.advanced} />
        <StatBlock label="Optional" value={summary.optional} />
      </div>

      <div className="dt-stats dt-stats-meta">
        <StatBlock label="Total caps" value={summary.total_caps} />
        <StatBlock label="Sub-modules" value={summary.sub_modules} />
        <StatBlock label="AI examples" value={summary.ai_features} />
      </div>
    </article>
  );
}
