import { useMemo, useState } from "react";
import type {
  ModuleEntry,
  PerModuleView,
  PerModuleTierData,
  SubModuleToSolCats,
  OnboardingMatrixCell,
  ReEvalFlag,
  SubModuleVerdict,
} from "../lib/stakeholdersData";
import "./PerModuleDeepDive.css";

export interface Props {
  modules: ModuleEntry[];
  perModuleViews: Record<string, PerModuleView>;
  proxyIdToName: Record<string, string>;
}

type TierKey = "required" | "required_preferred" | "all";

const TIER_LABEL: Record<TierKey, string> = {
  required: "Required only",
  required_preferred: "Required + Preferred",
  all: "All tiers",
};

const VERDICT_LABEL: Record<string, string> = {
  truly_generic: "Universal",
  mostly_generic: "Common",
  mixed: "Conditional",
  industry_specific: "Specialty",
};

function moduleShort(slug: string, modules: ModuleEntry[]): string {
  const m = modules.find(x => x.slug === slug);
  return m ? (m.short || m.name || slug) : slug;
}

function VerdictChip({ verdict, pct }: { verdict?: SubModuleVerdict; pct?: number }) {
  if (!verdict) return null;
  const label = VERDICT_LABEL[verdict] || verdict;
  return (
    <span className={`pmd-verdict pmd-verdict-${verdict}`} title={`${pct ?? 0}% caps generic`}>
      {label}
    </span>
  );
}

function tierMixTag(mix?: { r: number; p: number; a: number }): string {
  if (!mix) return "";
  const parts: string[] = [];
  if (mix.r > 0) parts.push(`${mix.r}R`);
  if (mix.p > 0) parts.push(`${mix.p}P`);
  if (mix.a > 0) parts.push(`${mix.a}A`);
  return parts.length ? `[${parts.join(" · ")}]` : "";
}

function cellLabelClass(label: string): string {
  if (label === "covers") return "covers";
  if (label === "no") return "no";
  if (label === "no_required") return "no_required";
  if (label === "n/a") return "na";
  return "mixed";
}

function CellBody({ cell, tier }: { cell: OnboardingMatrixCell; tier: TierKey }) {
  const cls = cellLabelClass(cell.label);
  if (cls === "na") return <span>—</span>;
  const parts: string[] = [];
  if (cell.r_total > 0) parts.push(`${cell.r_yes + cell.r_partial}/${cell.r_total} R`);
  if (cell.p_total > 0 && tier !== "required") parts.push(`${cell.p_yes + cell.p_partial}/${cell.p_total} P`);
  if (cell.a_total > 0 && tier === "all") parts.push(`${cell.a_yes + cell.a_partial}/${cell.a_total} A`);
  if (parts.length === 0) return <span>—</span>;
  const inner = parts.join(" · ");
  if (cls === "covers") return <span>✓ {inner}</span>;
  if (cls === "no") return <span>✗ {inner}</span>;
  return <span>{inner}</span>;
}

function buildCellTooltip(cell: OnboardingMatrixCell): string {
  if (cell.label === "n/a") return "n/a — no caps in this sub-module for this sol cat";
  const tierSummary: string[] = [];
  if (cell.r_total > 0) tierSummary.push(`R: ${cell.r_yes} yes · ${cell.r_partial} partial · ${cell.r_no} no (${cell.r_total} total)`);
  if (cell.p_total > 0) tierSummary.push(`P: ${cell.p_yes} yes · ${cell.p_partial} partial · ${cell.p_no} no (${cell.p_total} total)`);
  if (cell.a_total > 0) tierSummary.push(`A: ${cell.a_yes} yes · ${cell.a_partial} partial · ${cell.a_no} no (${cell.a_total} total)`);
  return `${cell.label} — ${cell.pct}%\n${tierSummary.join("\n")}`;
}

interface ModuleVerdict {
  label: "PASS" | "PARTIAL" | "FAIL" | "N/A";
  totalRSm: number;
  completeRSm: number;
}

function moduleVerdict(row: { sub_modules: Record<string, OnboardingMatrixCell> }): ModuleVerdict {
  const cells = Object.values(row.sub_modules || {}).filter(c => c && c.r_total > 0);
  const total = cells.length;
  if (total === 0) return { label: "N/A", totalRSm: 0, completeRSm: 0 };
  const complete = cells.filter(c => c.r_yes + c.r_partial === c.r_total).length;
  if (complete === total) return { label: "PASS", totalRSm: total, completeRSm: complete };
  if (complete > 0) return { label: "PARTIAL", totalRSm: total, completeRSm: complete };
  return { label: "FAIL", totalRSm: total, completeRSm: complete };
}

// ──────────────────────────────────────────────────────────────────────

export function PerModuleDeepDive({ modules, perModuleViews, proxyIdToName }: Props) {
  const [activeSlug, setActiveSlug] = useState<string>(modules[0]?.slug || "");
  const [tierFilter, setTierFilter] = useState<TierKey>("required");

  const pmv = perModuleViews[activeSlug];
  const moduleData = modules.find(m => m.slug === activeSlug);

  const tierSlice: PerModuleTierData = useMemo(() => {
    if (!pmv) return { caps_in_tier: 0, sub_module_to_solcats: [], onboarding_matrix: [] };
    return pmv.tiers[tierFilter] || pmv.tiers.all || pmv.tiers.required || { caps_in_tier: 0, sub_module_to_solcats: [], onboarding_matrix: [] };
  }, [pmv, tierFilter]);

  return (
    <section className="pmd-section">
      <header className="pmd-head">
        <h2 className="pmd-h2">
          <span className="pmd-num">§Per-module</span>
          Per-module deep dive
        </h2>
        <p className="pmd-sub">
          Five-step build chain story for any single module: how the caps were
          produced, what the checklist looks like, which sol cats back each
          sub-module, the vendor onboarding matrix, and any re-evaluation flags.
        </p>
      </header>

      <div className="pmd-pills">
        {modules.map(m => (
          <button
            key={m.slug}
            type="button"
            className={`pmd-pill${activeSlug === m.slug ? " active" : ""}`}
            onClick={() => setActiveSlug(m.slug)}
          >
            {m.short || m.name}
          </button>
        ))}
      </div>

      <div className="pmd-tier-bar">
        <span className="pmd-tier-label">Tier slice</span>
        {(Object.keys(TIER_LABEL) as TierKey[]).map(t => (
          <button
            key={t}
            type="button"
            className={`pmd-tier-pill${tierFilter === t ? " active" : ""}`}
            aria-pressed={tierFilter === t}
            onClick={() => setTierFilter(t)}
          >
            {TIER_LABEL[t]}
          </button>
        ))}
      </div>

      {!pmv || !moduleData ? (
        <div className="pmd-empty">No deep-dive data for this module yet.</div>
      ) : (
        <ModuleBody
          slug={activeSlug}
          moduleData={moduleData}
          pmv={pmv}
          tierSlice={tierSlice}
          tierKey={tierFilter}
          modules={modules}
          proxyIdToName={proxyIdToName}
        />
      )}
    </section>
  );
}

function ModuleBody({
  slug, moduleData, pmv, tierSlice, tierKey, modules: _modules, proxyIdToName,
}: {
  slug: string;
  moduleData: ModuleEntry;
  pmv: PerModuleView;
  tierSlice: PerModuleTierData;
  tierKey: TierKey;
  modules: ModuleEntry[];
  proxyIdToName: Record<string, string>;
}) {
  const totalCaps = pmv.cap_evidence.length;
  const reqCount = pmv.cap_evidence.filter(c => c.sme_tier === "required").length;
  const prefCount = pmv.cap_evidence.filter(c => c.sme_tier === "preferred").length;
  const advCount = pmv.cap_evidence.filter(c => c.sme_tier === "advanced").length;

  const sliceSubModules = tierSlice.sub_module_to_solcats || [];
  const subModulesCount = sliceSubModules.length;
  const universalCount = sliceSubModules.filter(s => s.verdict === "truly_generic" || s.verdict === "mostly_generic").length;
  const specialtyCount = sliceSubModules.filter(s => s.verdict === "industry_specific").length;

  // Step 2: caps grouped by sub-module — uses ALL slice for the summary table.
  const capsBySm = useMemo(() => {
    const m: Record<string, typeof pmv.cap_evidence> = {};
    const ungrouped: typeof pmv.cap_evidence = [];
    for (const c of pmv.cap_evidence) {
      if (c.sub_module_id) (m[c.sub_module_id] ||= []).push(c);
      else ungrouped.push(c);
    }
    return { byId: m, ungrouped };
  }, [pmv.cap_evidence]);
  const allSubModules = pmv.tiers.all?.sub_module_to_solcats || sliceSubModules;

  const flags = pmv.reeval_flags || tierSlice.flags || [];

  return (
    <>
      {/* ── Hero ─────────────────────────────────────────────────────── */}
      <div className="pmd-hero">
        <div className="pmd-hero-eyebrow">{moduleShort(slug, _modules)}</div>
        <h3 className="pmd-hero-name">{moduleData.name}</h3>
        <div className="pmd-hero-tagline">Vendor Self-Assessment Checklist</div>
        <div className="pmd-hero-stats">
          <div className="pmd-hero-stat">
            <div className="pmd-hero-num">{totalCaps} caps</div>
            <div className="pmd-hero-lbl">{reqCount} req · {prefCount} pref · {advCount} adv</div>
          </div>
          <div className="pmd-hero-stat">
            <div className="pmd-hero-num">{subModulesCount} sub-modules</div>
            <div className="pmd-hero-lbl">
              {universalCount} universal{specialtyCount > 0 ? ` · ${specialtyCount} specialty` : ""}
            </div>
          </div>
          <div className="pmd-hero-stat">
            <div className="pmd-hero-num">{pmv.build_chain.top_solcats.length} PSG sol cats</div>
            <div className="pmd-hero-lbl">contributed caps</div>
          </div>
          <div className="pmd-hero-stat">
            <div className="pmd-hero-num">{pmv.build_chain.top_proxies.length} ref ERPs</div>
            <div className="pmd-hero-lbl">cross-validated</div>
          </div>
        </div>
      </div>

      {/* ── Step 1: Build chain ──────────────────────────────────────── */}
      <div className="pmd-module-step pmd-step-1">
        <h3><span className="pmd-step-num">1</span>Build chain</h3>
        <p className="pmd-step-sub">
          Took these PSG sol cats × these reference ERPs to produce {totalCaps} caps. Each cap is traceable.
        </p>
        {pmv.build_chain.narrative && (
          <p className="pmd-narrative">{pmv.build_chain.narrative}</p>
        )}
        <div className="pmd-build-grid">
          <div>
            <h4 className="pmd-h4">PSG sol cats contributing</h4>
            <div className="pmd-list">
              {pmv.build_chain.top_solcats.slice(0, 12).map(sc => (
                <div key={sc.id} className="pmd-list-row">
                  <div>
                    {sc.display_name}
                    {sc.vertical_saas && <span className="pmd-vertical-chip">vertical</span>}
                  </div>
                  <div className="pmd-list-num">{sc.cap_count} caps</div>
                </div>
              ))}
            </div>
          </div>
          <div>
            <h4 className="pmd-h4">Reference ERPs cited</h4>
            <div className="pmd-list">
              {pmv.build_chain.top_proxies.slice(0, 12).map(p => (
                <div key={p.id} className="pmd-list-row" title={p.id}>
                  <div>{proxyIdToName[p.id] || p.id}</div>
                  <div className="pmd-list-num">{p.cap_count} caps</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* ── Step 2: Checklist summary ────────────────────────────────── */}
      <div className="pmd-module-step pmd-step-2">
        <h3><span className="pmd-step-num">2</span>The checklist · summary</h3>
        <p className="pmd-step-sub">
          {totalCaps} caps grouped by sub-module specialty. Tier mix:
          <strong> R</strong>equired · <strong>P</strong>referred · <strong>A</strong>dvanced.
          Full IMDA Type 1 checklist (with row IDs, closing benefits, AI Features, compliance,
          sector pills) lives in the canonical viewer.
        </p>
        <div className="pmd-summary-table">
          <div className="pmd-summary-row pmd-summary-head">
            <div>Sub-module</div>
            <div className="pmd-num">Caps</div>
            <div className="pmd-num">Tier mix</div>
            <div>Verdict</div>
          </div>
          {allSubModules.map(sm => {
            const smCaps = capsBySm.byId[sm.id] || [];
            if (smCaps.length === 0) return null;
            const r = smCaps.filter(c => c.sme_tier === "required").length;
            const p = smCaps.filter(c => c.sme_tier === "preferred").length;
            const a = smCaps.filter(c => c.sme_tier === "advanced").length;
            const tierMix: string[] = [];
            if (r > 0) tierMix.push(`${r}R`);
            if (p > 0) tierMix.push(`${p}P`);
            if (a > 0) tierMix.push(`${a}A`);
            return (
              <div key={sm.id} className="pmd-summary-row">
                <div className="pmd-sm-name">{sm.canonical_name}</div>
                <div className="pmd-num">{smCaps.length}</div>
                <div className="pmd-num pmd-tier-mix">{tierMix.join(" · ") || "—"}</div>
                <div><VerdictChip verdict={sm.verdict} pct={sm.pct_generic} /></div>
              </div>
            );
          })}
          {capsBySm.ungrouped.length > 0 && (
            <div className="pmd-summary-row">
              <div className="pmd-sm-name">Other (unassigned)</div>
              <div className="pmd-num">{capsBySm.ungrouped.length}</div>
              <div className="pmd-num pmd-tier-mix">—</div>
              <div></div>
            </div>
          )}
        </div>
        <a
          href={`/canonical_${slug}.html`}
          target="_blank"
          rel="noreferrer"
          className="pmd-canonical-link"
        >
          View full checklist for {moduleShort(slug, _modules)} →
        </a>
        <span className="pmd-canonical-note">Opens canonical viewer in a new window</span>
      </div>

      {/* ── Step 3: Sub-module ↔ sol cat mapping ─────────────────────── */}
      <div className="pmd-module-step pmd-step-3">
        <h3>
          <span className="pmd-step-num">3</span>
          Sub-module ↔ sol cat mapping{" "}
          <span className="pmd-step-tier">(filtered: {TIER_LABEL[tierKey]})</span>
        </h3>
        <p className="pmd-step-sub">
          How PSG's sol cats line up with this module's {subModulesCount} sub-modules at this
          tier. {universalCount} universal · {sliceSubModules.filter(s => s.verdict === "mixed").length} conditional · {specialtyCount} specialty.
        </p>
        <div className="pmd-step3-table">
          <div className="pmd-step3-row pmd-step3-head">
            <div>Sub-module</div>
            <div>Verdict</div>
            <div>PSG sol cats backing</div>
          </div>
          {sliceSubModules.length === 0 ? (
            <div className="pmd-empty-row">No sub-modules at this tier.</div>
          ) : (
            sliceSubModules.map((sm: SubModuleToSolCats) => (
              <div key={sm.id} className="pmd-step3-row">
                <div className="pmd-sm-name">{sm.canonical_name}</div>
                <div><VerdictChip verdict={sm.verdict} pct={sm.pct_generic} /></div>
                <div>
                  {sm.cap_count === 0 ? (
                    <span className="muted italic">no caps in this tier</span>
                  ) : sm.backing_solcats.length === 0 ? (
                    <span className="muted italic">no PSG sol cats — proxy-grounded</span>
                  ) : (
                    sm.backing_solcats.map(sc => (
                      <span key={sc.id} className="pmd-solcat-chip" title={sc.id}>
                        {sc.display_name}
                      </span>
                    ))
                  )}
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      {/* ── Step 4: Onboarding matrix ────────────────────────────────── */}
      <div className="pmd-module-step pmd-step-4">
        <h3>
          <span className="pmd-step-num">4</span>
          Vendor onboarding coverage matrix{" "}
          <span className="pmd-step-tier">(filtered: {TIER_LABEL[tierKey]})</span>
        </h3>
        <p className="pmd-step-sub">
          Sol cat × sub-module — Haiku-judged realistic coverage from data/solcat_fulfilment_realistic.yaml.
          Cell colour reflects Required-cap coverage; cell body shows tier-split fractions for the active filter.
        </p>
        <div
          className="pmd-matrix"
          style={{
            gridTemplateColumns: `minmax(200px,1.4fr) repeat(${sliceSubModules.length}, minmax(80px,1fr)) 100px`,
          }}
        >
          <div className="pmd-mc pmd-mc-corner">Sol cat</div>
          {sliceSubModules.map(sm => (
            <div key={sm.id} className="pmd-mc pmd-mc-col-head" title={sm.canonical_name}>
              <div className="pmd-mc-col-name">{sm.canonical_name}</div>
              {sm.tier_mix && <div className="pmd-mc-col-mix">{tierMixTag(sm.tier_mix)}</div>}
            </div>
          ))}
          <div className="pmd-mc pmd-mc-col-head pmd-mc-total">R complete</div>
          {tierSlice.onboarding_matrix.length === 0 ? (
            <div className="pmd-mc pmd-empty-row" style={{ gridColumn: "1 / -1" }}>
              No sol cats in scope at this tier.
            </div>
          ) : (
            tierSlice.onboarding_matrix.map(row => {
              const verdict = moduleVerdict(row);
              return (
                <RowChunk
                  key={row.id}
                  row={row}
                  subModules={sliceSubModules}
                  tierKey={tierKey}
                  verdict={verdict}
                />
              );
            })
          )}
        </div>
      </div>

      {/* ── Step 5: Re-evaluation flags ──────────────────────────────── */}
      {flags.length > 0 && (
        <div className="pmd-module-step pmd-step-5">
          <h3><span className="pmd-step-num">5</span>Re-evaluation flags</h3>
          <p className="pmd-step-sub">
            Auto-derived warnings from the build pipeline. Severity: high (red),
            medium (amber), low (slate), info (grey).
          </p>
          <div className="pmd-flags">
            {flags.map((f: ReEvalFlag, i: number) => (
              <div key={i} className={`pmd-flag pmd-flag-${f.severity || "info"}`}>
                <div className="pmd-flag-kind">{f.kind}</div>
                <div className="pmd-flag-msg">{f.msg}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </>
  );
}

function RowChunk({
  row, subModules, tierKey, verdict,
}: {
  row: { id: string; display_name: string; vertical?: string; vertical_saas?: boolean; is_primary: boolean; sub_modules: Record<string, OnboardingMatrixCell> };
  subModules: SubModuleToSolCats[];
  tierKey: TierKey;
  verdict: ModuleVerdict;
}) {
  return (
    <>
      <div className={`pmd-mc pmd-mc-row-head${row.is_primary ? "" : " pmd-mc-ride-along"}`} title={row.id}>
        <div className="pmd-mc-row-name">
          {row.display_name}
          {row.vertical_saas && <span className="pmd-vertical-chip">vertical</span>}
          {!row.is_primary && <span className="pmd-ride-chip">ride-along</span>}
        </div>
        {row.vertical && <div className="pmd-mc-row-vert">{row.vertical}</div>}
      </div>
      {subModules.map(sm => {
        const cell = row.sub_modules[sm.id] || {
          sm_id: sm.id, sm_name: sm.canonical_name,
          label: "n/a", pct: 0, yes: 0, partial: 0, no: 0, total: 0,
          r_yes: 0, r_partial: 0, r_no: 0, r_total: 0,
          p_yes: 0, p_partial: 0, p_no: 0, p_total: 0,
          a_yes: 0, a_partial: 0, a_no: 0, a_total: 0,
        };
        return (
          <div
            key={sm.id}
            className={`pmd-mc pmd-mc-data pmd-cell-${cellLabelClass(cell.label)}`}
            title={buildCellTooltip(cell)}
          >
            <CellBody cell={cell} tier={tierKey} />
          </div>
        );
      })}
      <div className={`pmd-mc pmd-mc-data pmd-mc-total-cell pmd-verdict-mod-${verdict.label.toLowerCase()}`}>
        {verdict.label === "N/A" ? "—" : `${verdict.completeRSm}/${verdict.totalRSm}`}
      </div>
    </>
  );
}
