/**
 * Pure diff helper for audit_log rows. Given the post-edit `fields` and
 * pre-edit `prior_fields`, returns one row per field changed/added/removed,
 * suitable for inline rendering in the editor and the Change log table.
 *
 * Rendering policy by kind:
 *   - "changed":      "<before> → <after>"
 *   - "added":        "(none) → <after>"
 *   - "removed":      "<before> → (none)"     (clear ops)
 *   - "set_no_prior": "<after> (prior not captured)"   (legacy / first-save)
 *
 * Both fields = null  →  empty list.
 * Prior fields = null and fields = non-null  →  one set_no_prior row per
 *                                              field in fields.
 */

export type FieldDiffKind = "changed" | "added" | "removed" | "set_no_prior";

export interface FieldDiffRow {
  field: string;
  kind: FieldDiffKind;
  before?: unknown;
  after?: unknown;
}

function valueEquals(a: unknown, b: unknown): boolean {
  if (a === b) return true;
  if (a === null || b === null || a === undefined || b === undefined) return false;
  if (typeof a !== "object" || typeof b !== "object") return false;
  return JSON.stringify(a) === JSON.stringify(b);
}

export function computeFieldDiff(
  priorFields: Record<string, unknown> | null,
  fields: Record<string, unknown> | null,
): FieldDiffRow[] {
  // Both null — nothing to render.
  if (!priorFields && !fields) return [];

  // Clear op: prior captured, new is null. Emit one removed row per prior key.
  if (priorFields && !fields) {
    return Object.keys(priorFields).map(field => ({
      field,
      kind: "removed",
      before: priorFields[field],
      after: undefined,
    }));
  }

  // Pre-0003 row or first save: new fields, no prior captured. Emit a
  // set_no_prior row per new field so the user sees what was set without
  // a misleading "(none) → value" implying the field was previously unset.
  if (!priorFields && fields) {
    return Object.keys(fields).map(field => ({
      field,
      kind: "set_no_prior",
      before: undefined,
      after: fields[field],
    }));
  }

  // Both present — full diff.
  const out: FieldDiffRow[] = [];
  const seen = new Set<string>();
  // Iterate new keys first (preserves insertion order for changed/added).
  for (const field of Object.keys(fields!)) {
    seen.add(field);
    const after = fields![field];
    if (!(field in priorFields!)) {
      out.push({ field, kind: "added", before: undefined, after });
    } else {
      const before = priorFields![field];
      if (!valueEquals(before, after)) {
        out.push({ field, kind: "changed", before, after });
      }
    }
  }
  // Then any keys removed (in prior but not in new).
  for (const field of Object.keys(priorFields!)) {
    if (seen.has(field)) continue;
    out.push({ field, kind: "removed", before: priorFields![field], after: undefined });
  }
  return out;
}
