import { useMemo, useState } from "react";
import type {
  ModuleEntry,
  CapEvidence,
  ProxyFulfilmentPayload,
  ProxyFulfilment,
} from "../lib/stakeholdersData";
import "./ErpScoreboard.css";

export interface Props {
  modules: ModuleEntry[];
  caps: CapEvidence[];
  proxyFulfilment: ProxyFulfilmentPayload;
  proxyIdToName: Record<string, string>;
}

const ALL = "__all__";

function scoreClass(pct: number): string {
  if (pct >= 80) return "high";
  if (pct >= 50) return "mid";
  if (pct > 0) return "low";
  return "zero";
}

function fulfilColor(f?: ProxyFulfilment): string {
  if (f === "yes") return "#10b981";
  if (f === "partial") return "#f59e0b";
  if (f === "no") return "#ef4444";
  return "#cbd5e1";
}
function fulfilGlyph(f?: ProxyFulfilment): string {
  if (f === "yes") return "✓";
  if (f === "partial") return "~";
  if (f === "no") return "✗";
  return "·";
}

interface ProxyAggregate {
  id: string;
  name: string;
  yes: number;
  partial: number;
  no: number;
  total: number;
  pct: number;
}

export function ErpScoreboard({ modules, caps, proxyFulfilment, proxyIdToName }: Props) {
  const [moduleFilter, setModuleFilter] = useState<string>(ALL);

  const proxyData = proxyFulfilment.caps || {};
  const totalScored = Object.keys(proxyData).length;

  const capModuleIdx = useMemo(() => {
    const m: Record<string, string> = {};
    for (const c of caps) m[c.id] = c.module;
    return m;
  }, [caps]);

  const capsInScope = useMemo(() => {
    return Object.keys(proxyData).filter(cid => {
      if (moduleFilter === ALL) return true;
      return capModuleIdx[cid] === moduleFilter;
    });
  }, [proxyData, moduleFilter, capModuleIdx]);

  const proxyAggregates = useMemo<ProxyAggregate[]>(() => {
    const agg: Record<string, { yes: number; partial: number; no: number; total: number }> = {};
    for (const cid of capsInScope) {
      const proxies = proxyData[cid] || {};
      for (const [pid, score] of Object.entries(proxies)) {
        const a = (agg[pid] ||= { yes: 0, partial: 0, no: 0, total: 0 });
        a.total += 1;
        if (score.fulfils === "yes") a.yes += 1;
        else if (score.fulfils === "partial") a.partial += 1;
        else if (score.fulfils === "no") a.no += 1;
      }
    }
    return Object.entries(agg)
      .filter(([, v]) => v.total > 0)
      .map(([pid, v]) => {
        const realisticScore = v.yes + 0.5 * v.partial;
        return {
          id: pid,
          name: proxyIdToName[pid] || pid,
          yes: v.yes,
          partial: v.partial,
          no: v.no,
          total: v.total,
          pct: Math.round((100 * realisticScore) / v.total),
        };
      })
      .sort((a, b) => b.pct - a.pct);
  }, [capsInScope, proxyData, proxyIdToName]);

  if (totalScored === 0) {
    return (
      <section className="eb-section">
        <header className="eb-head">
          <h2 className="eb-h2">
            <span className="eb-num">§5</span>
            Reference ERP scoreboard
          </h2>
          <p className="eb-sub">
            For each reference ERP we cite, how many caps in the checklist its documentation
            actually fulfils.
          </p>
        </header>
        <div className="eb-stub">
          <div className="eb-stub-tag">Pending — T3-γ1</div>
          <p><strong>Fulfilment scoring not yet run.</strong></p>
          <p className="eb-stub-cmd">
            Run <code>python3 scripts/score_proxy_fulfilment.py</code> (~$2.30 Haiku) and
            rebuild this viewer.
          </p>
        </div>
      </section>
    );
  }

  const top15 = proxyAggregates.slice(0, 15);
  const top15Ids = top15.map(p => p.id);
  const totalPairs = proxyAggregates.reduce((acc, p) => acc + p.total, 0);
  const lastUpdated = proxyFulfilment._meta?.last_updated;
  const heatmapCaps = capsInScope.slice(0, 60);
  const heatmapLimited = capsInScope.length > 60;

  return (
    <section className="eb-section">
      <header className="eb-head">
        <h2 className="eb-h2">
          <span className="eb-num">§5</span>
          Reference ERP scoreboard
        </h2>
        <p className="eb-sub">
          For each reference ERP we cite, what fraction of caps in scope its documented
          capabilities fulfil. <strong>Haiku-scored snapshot, not vendor-confirmed.</strong>
          Realistic % = (yes + 0.5 × partial) ÷ pairs scored. Filter by module to compare
          ERPs within a single domain.
        </p>
      </header>

      <div className="eb-controls">
        <label htmlFor="eb-mod">Module scope</label>
        <select
          id="eb-mod"
          value={moduleFilter}
          onChange={e => setModuleFilter(e.target.value)}
        >
          <option value={ALL}>All modules (global)</option>
          {modules.map(m => (
            <option key={m.slug} value={m.slug}>{m.short || m.name}</option>
          ))}
        </select>
        <span className="eb-count-note">
          {capsInScope.length} caps · {proxyAggregates.length} ref ERPs · {totalPairs} pairs scored
          {moduleFilter !== ALL && ` (filtered)`}
        </span>
      </div>

      <h3 className="eb-h3">Top 15 reference ERPs by realistic fulfilment</h3>
      <div className="eb-leaderboard">
        <div className="eb-leaderboard-row eb-leaderboard-head">
          <div>Reference ERP</div>
          <div className="eb-num">Pairs</div>
          <div className="eb-num">Yes</div>
          <div className="eb-num">Partial</div>
          <div className="eb-num">No</div>
          <div className="eb-num">Realistic %</div>
        </div>
        {top15.map(p => (
          <div key={p.id} className="eb-leaderboard-row" title={p.id}>
            <div className="eb-name">{p.name}</div>
            <div className="eb-num">{p.total}</div>
            <div className="eb-num eb-good">{p.yes}</div>
            <div className="eb-num eb-warn">{p.partial}</div>
            <div className="eb-num eb-bad">{p.no}</div>
            <div className="eb-num">
              <span className={`eb-score eb-score-${scoreClass(p.pct)}`}>{p.pct}%</span>
            </div>
          </div>
        ))}
      </div>

      <details className="eb-heatmap">
        <summary>
          <span className="eb-tri" aria-hidden="true">▸</span>
          Per-cap heatmap (top {top15Ids.length} reference ERPs × {heatmapCaps.length} caps)
          {heatmapLimited && (
            <span className="eb-heatmap-note">
              — first 60 of {capsInScope.length} caps shown
            </span>
          )}
        </summary>
        <div className="eb-heatmap-legend">
          Hover any cell for the cap × ERP score + Haiku reason. ✓ = yes (green) · ~ = partial
          (amber) · ✗ = no (red) · · = not scored.
        </div>
        <div
          className="eb-heatmap-grid"
          style={{
            gridTemplateColumns: `minmax(180px, 1.4fr) repeat(${top15Ids.length}, minmax(22px, 1fr))`,
          }}
        >
          <div className="eb-heatmap-cell eb-heatmap-corner">Cap</div>
          {top15Ids.map(pid => (
            <div
              key={pid}
              className="eb-heatmap-cell eb-heatmap-col-head"
              title={pid}
            >
              {(proxyIdToName[pid] || pid).slice(0, 22)}
            </div>
          ))}
          {heatmapCaps.map(cid => {
            const cap = caps.find(c => c.id === cid);
            const capName = cap?.name || cid;
            return (
              <>
                <div key={`${cid}-name`} className="eb-heatmap-cell eb-heatmap-row-head" title={cid}>
                  {capName}
                </div>
                {top15Ids.map(pid => {
                  const score = (proxyData[cid] || {})[pid];
                  const f = score?.fulfils;
                  const reason = (score?.reason || "").slice(0, 100);
                  return (
                    <div
                      key={`${cid}-${pid}`}
                      className="eb-heatmap-cell eb-heatmap-data"
                      style={{ background: fulfilColor(f) }}
                      title={`${proxyIdToName[pid] || pid} · ${f || "not scored"} — ${reason}`}
                    >
                      {fulfilGlyph(f)}
                    </div>
                  );
                })}
              </>
            );
          })}
        </div>
      </details>

      {lastUpdated && (
        <div className="eb-footer">
          Last scored: {lastUpdated.slice(0, 10)} · Haiku 4.5 snapshot
        </div>
      )}
    </section>
  );
}
