/**
 * Dashboard summary — pre-computed per-module counts the SPA Home renders.
 *
 * Source: scripts/build_dashboard_summary.py emits output/dashboard_summary.json
 * after every pipeline change that affects cap counts. The SPA fetches it once
 * (cached) so the dashboard renders instantly without 10 canonical-JSON
 * round-trips.
 */

export interface ModuleSummary {
  name: string;
  required: number;
  preferred: number;
  advanced: number;
  optional: number;
  total_caps: number;
  sub_modules: number;
  ai_features: number;
}

export interface DashboardSummary {
  generated_at: string;
  modules: Record<string, ModuleSummary>;
}

let _cache: DashboardSummary | null = null;
let _inflight: Promise<DashboardSummary> | null = null;

export async function loadDashboardSummary(): Promise<DashboardSummary> {
  if (_cache) return _cache;
  if (_inflight) return _inflight;
  _inflight = fetch("/dashboard_summary.json", { credentials: "same-origin" })
    .then(res => {
      if (!res.ok) throw new Error(`dashboard_summary fetch failed: ${res.status}`);
      return res.json() as Promise<DashboardSummary>;
    })
    .then(payload => {
      _cache = payload;
      _inflight = null;
      return payload;
    })
    .catch(e => {
      _inflight = null;
      throw e;
    });
  return _inflight;
}

export function _resetDashboardSummaryCache(): void {
  _cache = null;
  _inflight = null;
}
