import { useState } from "react";
import { Link } from "react-router-dom";
import { MODULES } from "../lib/modules";
import "./NavBar.css";

/**
 * Active selector — controls which item is aria-current="page" + visually
 * highlighted. Pass:
 *   "overview"      for the Home / dashboard route
 *   "stakeholders"  for the StakeholdersPage
 *   "<module-slug>" for any per-module canonical page
 *   undefined       to render the nav with nothing flagged active
 */
type ActiveItem = "overview" | "stakeholders" | string;

export interface Props {
  active?: ActiveItem;
}

// BUILD tools entries are still served by the legacy HTML viewers — these
// links navigate out of the SPA to the legacy URLs. Once the SPA absorbs
// these surfaces (BUILD-tools authoring isn't in scope today) the dropdown
// re-points at SPA routes.
const BUILD_TOOLS_LINKS: Array<{ label: string; href: string }> = [
  { label: "Methodology (legacy)", href: "/methodology.html" },
  { label: "Use cases (legacy)",   href: "/use_cases.html" },
  { label: "Gap analysis (legacy)", href: "/gap_analysis.html" },
  { label: "Pipeline (legacy)",    href: "/pipeline.html" },
  { label: "Integrations (legacy)", href: "/integrations.html" },
];

function navLinkProps(active: boolean) {
  return {
    className: `topbar-link${active ? " active" : ""}`,
    ...(active ? { "aria-current": "page" as const } : {}),
  };
}

export function NavBar({ active }: Props) {
  const [buildOpen, setBuildOpen] = useState(false);

  return (
    <nav className="topbar" aria-label="Main navigation">
      <div className="topbar-inner">
        <span className="topbar-brand">ERP Mapper</span>

        <Link to="/" {...navLinkProps(active === "overview")}>
          Overview
        </Link>
        <Link to="/dashboard" {...navLinkProps(active === "dashboard")}>
          Dashboard
        </Link>
        <Link to="/stakeholders" {...navLinkProps(active === "stakeholders")}>
          Stakeholders
        </Link>

        <span className="topbar-sep" aria-hidden="true" />

        {MODULES.map(m => (
          <Link
            key={m.slug}
            to={`/canonical/${m.slug}`}
            {...navLinkProps(active === m.slug)}
          >
            {m.short}
          </Link>
        ))}

        <span className="topbar-sep" aria-hidden="true" />

        <div className="topbar-dropdown-wrap">
          <button
            type="button"
            className="topbar-link topbar-dropdown-trigger"
            aria-expanded={buildOpen}
            aria-haspopup="menu"
            onClick={() => setBuildOpen(v => !v)}
            onBlur={() => setTimeout(() => setBuildOpen(false), 120)}
          >
            BUILD tools ▾
          </button>
          {buildOpen && (
            <div className="topbar-dropdown-menu" role="menu">
              {BUILD_TOOLS_LINKS.map(l => (
                <a
                  key={l.href}
                  href={l.href}
                  role="menuitem"
                  className="topbar-dropdown-item"
                >
                  {l.label}
                </a>
              ))}
            </div>
          )}
        </div>
      </div>
    </nav>
  );
}
