import type { StakeholdersSummary } from "../lib/stakeholdersData";
import "./MethodologySection.css";

export interface Props {
  summary: StakeholdersSummary;
}

interface KpiStat {
  num: number;
  label: string;
}

interface Principle {
  title: string;
  body: string;
}

export function MethodologySection({ summary }: Props) {
  const k = summary.kpis;
  const excludedNote = k.sol_cats_excluded > 0 ? ` (${k.sol_cats_excluded} excluded as non-ERP)` : "";

  const stats: KpiStat[] = [
    { num: k.sol_cats, label: `PSG sol cats analysed${excludedNote}` },
    { num: k.raw_requirements, label: "raw requirements parsed" },
    { num: k.unique_caps, label: "deduped capabilities" },
    { num: k.modules, label: "ERP modules" },
    { num: k.proxy_erps, label: "reference ERPs cross-validated" },
    { num: k.psg_solutions, label: "PSG-approved solutions linked" },
  ];

  const principles: Principle[] = [
    {
      title: "Curated, not scraped",
      body: "Every checklist row carries a documented derivation chain — IMDA sol cat → question → cap. Click any row to read its sources.",
    },
    {
      title: "Cross-validated",
      body: `Each cap is independently confirmed against ${k.proxy_erps}+ reference ERPs (NetSuite, Odoo, ERPNext, SAP, Oracle, Microsoft Dynamics) plus mainstream encyclopedic sources.`,
    },
    {
      title: "Sectorally specific",
      body: "Sector relevance is scored per cap within the sectors a module actually applies to (L1+L2 layering) — not generic boilerplate.",
    },
    {
      title: "Round-trippable to PSG",
      body: "Section 4 below scores each PSG sol cat against the checklist it should produce — a draft enhancement memo for IMDA.",
    },
  ];

  return (
    <section className="ms-section">
      <header className="ms-hero">
        <h1>How this ERP checklist was built</h1>
        <p className="ms-pitch">
          An evidence-grounded vendor-qualification checklist for Singapore SMEs — derived from
          the IMDA PSG pre-approval guide, cross-validated against {k.proxy_erps}+ reference ERPs,
          and round-trippable to the {k.psg_solutions} PSG-approved solutions in the catalogue.
          Curated, not scraped.
        </p>
        <div className="ms-stat-strip">
          {stats.map(s => (
            <div key={s.label} className="ms-stat">
              <div className="ms-stat-num">{s.num.toLocaleString()}</div>
              <div className="ms-stat-lbl">{s.label}</div>
            </div>
          ))}
        </div>
      </header>

      <div className="ms-taxonomy">
        <span className="ms-taxonomy-eyebrow">Our taxonomy</span>
        {k.modules || 10} ERP modules + ~60 vendor-specialty sub-modules — derived from
        major-suite convention (NetSuite, SAP, Oracle, Microsoft Dynamics, Odoo, Workday,
        Sage). Sub-modules represent coherent vendor specialties a PSG buyer can qualify
        independently. Full definitions in <code>config/erp_modules.yaml</code> +
        <code> config/sub_modules.yaml</code>.
      </div>

      <h2 className="ms-h2"><span className="ms-num">§1</span>Methodology</h2>
      <p className="ms-sub">
        Six-stage data pipeline that converts PSG's published catalogue + reference ERP
        documentation into a single sector-aware vendor-qualification checklist. Each stage
        is named after its data-science analogue so technical and non-technical readers see
        the same picture.
      </p>

      <ol className="ms-pipeline">
        {summary.pipeline_stages.slice(0, 6).map((s, i) => (
          <li key={s.name} className="ms-stage">
            <div className="ms-stage-step">Stage {i + 1}</div>
            <div className="ms-stage-name">{s.name}</div>
            <div className="ms-stage-ds" title="Data-science analogue">{s.ds_analogue}</div>
            <div className="ms-stage-desc">{s.plain_description}</div>
            {s.stat && <div className="ms-stage-stat">{s.stat}</div>}
          </li>
        ))}
      </ol>

      <div className="ms-principles">
        {principles.map(p => (
          <div key={p.title} className="ms-principle">
            <div className="ms-principle-title">{p.title}</div>
            <div className="ms-principle-body">{p.body}</div>
          </div>
        ))}
      </div>
    </section>
  );
}
