import type { CanonicalModule } from "../types/canonical";

/**
 * Fetch a canonical module's JSON payload. The file lives at
 * /canonical/<module>.json on the same origin (the Cloudflare Worker
 * serves it via the [assets] binding from output/canonical/).
 *
 * The static-assets binding is publicly served on the same domain as the
 * SPA, so a fetch with credentials: "same-origin" picks up the Cloudflare
 * Access cookie automatically — no cross-origin gymnastics.
 */
export async function loadCanonicalModule(slug: string): Promise<CanonicalModule> {
  const res = await fetch(`/canonical/${encodeURIComponent(slug)}.json`, {
    credentials: "same-origin",
  });
  if (!res.ok) {
    throw new Error(`canonical fetch failed for ${slug}: ${res.status}`);
  }
  return res.json() as Promise<CanonicalModule>;
}
