import { useMemo, useState } from "react";
import type {
  ModuleEntry,
  CapEvidence,
  ModuleImdaQuestion,
  ModuleImdaSummary,
} from "../lib/stakeholdersData";
import "./EvidenceDrill.css";

export interface Props {
  modules: ModuleEntry[];
  caps: CapEvidence[];
  moduleImdaQuestions: Record<string, ModuleImdaQuestion[]>;
  moduleImdaSummary: Record<string, ModuleImdaSummary>;
  proxyIdToName: Record<string, string>;
}

type SubView = "cap" | "module";

// Tier label + class come from the central src/lib/tier.ts.
import { tierLabel, tierClass } from "../lib/tier";

function moduleShort(slug: string, modules: ModuleEntry[]): string {
  const m = modules.find(x => x.slug === slug);
  return m ? (m.short || m.name || slug) : slug;
}

export function EvidenceDrill({
  modules,
  caps,
  moduleImdaQuestions,
  moduleImdaSummary,
  proxyIdToName,
}: Props) {
  const [subView, setSubView] = useState<SubView>("cap");
  const [selectedCapId, setSelectedCapId] = useState<string>(() => caps[0]?.id || "");
  const [selectedModuleSlug, setSelectedModuleSlug] = useState<string>(
    () => modules[0]?.slug || "",
  );

  const subTabs = (
    <div className="ed-subtabs" aria-label="Evidence drill view">
      <button
        type="button"
        className={`ed-subtab${subView === "cap" ? " active" : ""}`}
        aria-pressed={subView === "cap"}
        onClick={() => setSubView("cap")}
      >
        Cap → sources
      </button>
      <button
        type="button"
        className={`ed-subtab${subView === "module" ? " active" : ""}`}
        aria-pressed={subView === "module"}
        onClick={() => setSubView("module")}
      >
        Module → IMDA questions
      </button>
    </div>
  );

  return (
    <section className="ed-section">
      <header className="ed-head">
        <h2 className="ed-h2">
          <span className="ed-num">§3</span>
          Per-cap evidence
        </h2>
        <p className="ed-sub">
          Two lenses: <strong>Cap → sources</strong> shows the IMDA + reference ERP +
          sector evidence behind one capability. <strong>Module → IMDA questions</strong>
          answers "which IMDA questions relate to this ERP module" — every distinct
          question grouped by sol cat with the caps each one produced.
        </p>
        {subTabs}
      </header>

      {subView === "cap" ? (
        <CapSourcesView
          modules={modules}
          caps={caps}
          selectedCapId={selectedCapId}
          onSelectCap={setSelectedCapId}
          proxyIdToName={proxyIdToName}
        />
      ) : (
        <ModuleQuestionsView
          modules={modules}
          moduleImdaQuestions={moduleImdaQuestions}
          moduleImdaSummary={moduleImdaSummary}
          selectedModuleSlug={selectedModuleSlug}
          onSelectModule={setSelectedModuleSlug}
        />
      )}
    </section>
  );
}

// ──────────────────────────────────────────────────────────────────────
// Cap → sources view
// ──────────────────────────────────────────────────────────────────────

function CapSourcesView({
  modules,
  caps,
  selectedCapId,
  onSelectCap,
  proxyIdToName,
}: {
  modules: ModuleEntry[];
  caps: CapEvidence[];
  selectedCapId: string;
  onSelectCap: (id: string) => void;
  proxyIdToName: Record<string, string>;
}) {
  const selected = caps.find(c => c.id === selectedCapId) || caps[0];
  const capsByModule = useMemo(() => {
    const m: Record<string, CapEvidence[]> = {};
    for (const c of caps) (m[c.module] ||= []).push(c);
    return m;
  }, [caps]);

  if (!selected) {
    return <div className="ed-msg muted">No capability data — re-run the canonicalise pipeline.</div>;
  }

  const sectorRel = selected.sector_relevance || {};
  const sectors = sectorRel.sectors || {};
  const scope = sectorRel.scope_sectors || Object.keys(sectors);
  const relevantCount = Object.values(sectors).filter(s => s && s.relevant).length;

  return (
    <>
      <div className="ed-cap-picker">
        <label htmlFor="ed-cap-select" className="ed-picker-label">Pick a capability</label>
        <select
          id="ed-cap-select"
          value={selected.id}
          onChange={e => onSelectCap(e.target.value)}
        >
          {Object.entries(capsByModule).map(([slug, list]) => (
            <optgroup key={slug} label={`${moduleShort(slug, modules)} (${list.length})`}>
              {list.map(c => (
                <option key={c.id} value={c.id}>
                  {c.name}{c.sub_module_name ? ` — ${c.sub_module_name}` : ""}
                </option>
              ))}
            </optgroup>
          ))}
        </select>
      </div>

      <article className="ed-evidence">
        <h3 className="ed-cap-name">{selected.name}</h3>
        <div className="ed-cap-meta">
          {moduleShort(selected.module, modules)} · {selected.family || "—"}
          {" · "}
          <strong className={`ed-tier ${tierClass(selected.sme_tier)} tier-text`}>
            {tierLabel(selected.sme_tier)}
          </strong>
          {selected.sub_module_id && (
            <div className="ed-submod">
              Sub-module: <strong>{selected.sub_module_name || selected.sub_module_id}</strong>
              {selected.sub_module_description && (
                <span className="muted"> — {selected.sub_module_description}</span>
              )}
            </div>
          )}
        </div>

        {selected.question && (
          <div className="ed-cap-q">
            <strong>Vendor question:</strong> {selected.question}
          </div>
        )}

        <div className="ed-grid">
          <div className="ed-col">
            <h4>IMDA provenance · {selected.imda_refs.length} ref{selected.imda_refs.length === 1 ? "" : "s"}</h4>
            {selected.imda_refs.length === 0 ? (
              <div className="ed-ref-item muted italic">
                No IMDA references — this cap was confirmed by reference ERPs only (proxy-grounded).
              </div>
            ) : (
              selected.imda_refs.slice(0, 12).map((r, i) => (
                <div key={i} className="ed-ref-item">
                  <span className="ed-ref-label">IMDA Q</span>
                  <div className="ed-ref-q">{r.q_title}</div>
                  <div className="ed-ref-sc">
                    {(r.sources || []).slice(0, 4).map(s => s.split("__").pop()).join(" · ")}
                  </div>
                </div>
              ))
            )}
          </div>

          <div className="ed-col">
            <h4>Reference ERP citations · {selected.vendor_citations.length}</h4>
            {selected.vendor_citations.length === 0 ? (
              <div className="ed-ref-item muted italic">
                No reference ERP citations recorded.
              </div>
            ) : (
              <div className="ed-ref-item">
                <span className="ed-ref-label">
                  Reference ERPs that document this capability
                </span>
                <div className="ed-vendor-chips">
                  {selected.vendor_citations.slice(0, 18).map(v => (
                    <span key={v} className="ed-vendor-chip" title={v}>
                      {proxyIdToName[v] || v}
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="ed-sector-block">
          <h4>
            Sector relevance · {relevantCount}/{scope.length} sectors
          </h4>
          {scope.length === 0 ? (
            <div className="ed-ref-item muted italic">
              No sector relevance data for this capability.
            </div>
          ) : (
            <div className="ed-sector-heatmap">
              {scope.map(s => {
                const entry = sectors[s];
                const relevant = entry && entry.relevant === true;
                return (
                  <div
                    key={s}
                    className={`ed-sector-cell${relevant ? " relevant" : ""}`}
                    title={(entry && entry.reason) || ""}
                  >
                    {s}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </article>
    </>
  );
}

// ──────────────────────────────────────────────────────────────────────
// Module → IMDA questions view
// ──────────────────────────────────────────────────────────────────────

function ModuleQuestionsView({
  modules,
  moduleImdaQuestions,
  moduleImdaSummary,
  selectedModuleSlug,
  onSelectModule,
}: {
  modules: ModuleEntry[];
  moduleImdaQuestions: Record<string, ModuleImdaQuestion[]>;
  moduleImdaSummary: Record<string, ModuleImdaSummary>;
  selectedModuleSlug: string;
  onSelectModule: (slug: string) => void;
}) {
  const rows = moduleImdaQuestions[selectedModuleSlug] || [];

  // Group by sol cat for the accordion.
  const bySolCat = useMemo(() => {
    const m: Record<string, ModuleImdaQuestion[]> = {};
    for (const r of rows) (m[r.sol_cat] ||= []).push(r);
    return m;
  }, [rows]);
  const solCatNames = Object.keys(bySolCat).sort();

  const activeModule = modules.find(m => m.slug === selectedModuleSlug);

  return (
    <>
      <h3 className="ed-section-h3">Coverage by module</h3>
      <div className="ed-summary-table">
        <div className="ed-summary-row ed-summary-head">
          <div>Module</div>
          <div className="num">Caps</div>
          <div className="num">IMDA-driven</div>
          <div className="num">Proxy-only</div>
          <div>Top 3 contributing sol cats</div>
        </div>
        {modules.map(m => {
          const s = moduleImdaSummary[m.slug] || {
            total_caps: 0, imda_driven_count: 0, proxy_only_count: 0, top_solcats: [],
          };
          const proxyPct = s.total_caps ? Math.round((100 * s.proxy_only_count) / s.total_caps) : 0;
          const proxyTone = proxyPct >= 50 ? "warn-high" : proxyPct >= 25 ? "warn-low" : "";
          const isActive = m.slug === selectedModuleSlug;
          return (
            <div
              key={m.slug}
              data-module-summary-slug={m.slug}
              className={`ed-summary-row${isActive ? " active" : ""}`}
              onClick={() => onSelectModule(m.slug)}
              role="button"
              tabIndex={0}
              onKeyDown={e => {
                if (e.key === "Enter" || e.key === " ") {
                  e.preventDefault();
                  onSelectModule(m.slug);
                }
              }}
            >
              <div className="ed-summary-name">{m.short || m.name || m.slug}</div>
              <div className="num">{s.total_caps}</div>
              <div className="num good">{s.imda_driven_count}</div>
              <div className={`num ${proxyTone}`}>
                {s.proxy_only_count} <span className="pct">({proxyPct}%)</span>
              </div>
              <div className="ed-top-solcats">
                {s.top_solcats.length === 0 ? (
                  <span className="muted italic">no PSG sol cats — proxy-grounded</span>
                ) : (
                  s.top_solcats.map(t => (
                    <span key={t.sol_cat} className="ed-solcat-chip" title={t.sol_cat}>
                      {t.sol_cat_short} <span className="pct">{t.cap_count}</span>
                    </span>
                  ))
                )}
              </div>
            </div>
          );
        })}
      </div>

      <h3 className="ed-section-h3 ed-spaced">
        Drill-down: {activeModule?.short || selectedModuleSlug} — IMDA questions per sol cat
      </h3>
      <div className="ed-cap-picker">
        <label htmlFor="ed-mod-q-select" className="ed-picker-label">Module</label>
        <select
          id="ed-mod-q-select"
          value={selectedModuleSlug}
          onChange={e => onSelectModule(e.target.value)}
        >
          {modules.map(m => {
            const qsCount = (moduleImdaQuestions[m.slug] || []).length;
            return (
              <option key={m.slug} value={m.slug}>
                {m.short || m.name || m.slug} ({qsCount} qs)
              </option>
            );
          })}
        </select>
        <span className="ed-count-note">
          {rows.length} distinct IMDA questions across {solCatNames.length} sol cats. Click any sol cat to expand.
        </span>
      </div>

      {solCatNames.length === 0 ? (
        <div className="ed-empty">No IMDA questions traced for this module yet.</div>
      ) : (
        solCatNames.map(sc => {
          const qs = bySolCat[sc];
          const sample = qs[0];
          const verticalLabel = sc.split("__")[0].replace(/-/g, " ");
          return (
            <details key={sc} className="ed-solcat-block">
              <summary>
                <span>
                  <span className="ed-tri">▸</span>
                  {verticalLabel} ·{" "}
                  <span className="muted">{sample.sol_cat_short}</span>
                </span>
                <span className="ed-q-count">
                  {qs.length} q{qs.length === 1 ? "" : "s"}
                </span>
              </summary>
              {qs.map((q, i) => (
                <div key={i} className="ed-q-row">
                  <div className="ed-q-title">{q.q_title}</div>
                  <div className="ed-q-caps-label">
                    Caps produced ({q.caps.length})
                  </div>
                  <div className="ed-q-caps">
                    {q.caps.map(c => (
                      <span key={c.id} className="ed-cap-chip" title={c.id}>
                        {c.name}
                      </span>
                    ))}
                  </div>
                </div>
              ))}
            </details>
          );
        })
      )}
    </>
  );
}
