import { useMemo, useState } from "react";
import type {
  ModuleEntry,
  SolCatRow,
  SubModuleChip,
  ExcludedSolCat,
  SubModuleSpecificity,
} from "../lib/stakeholdersData";
import "./CoverageMap.css";

export interface Props {
  modules: ModuleEntry[];
  solCats: SolCatRow[];
  excludedSolCats: ExcludedSolCat[];
  exclusionGroups: Record<string, string>;
  submoduleSpecificity: Record<string, SubModuleSpecificity>;
}

const VERDICT_LABEL: Record<string, string> = {
  truly_generic: "Universal",
  mostly_generic: "Common",
  mixed: "Conditional",
  industry_specific: "Specialty",
};

const EXCLUSION_GROUP_LABEL: Record<string, string> = {
  cybersecurity: "Cybersecurity",
  utility_ai: "Utility / AI",
  legal_point_tool: "Legal point-tools",
  bi_point_tool: "BI / analytics point-tools",
};

const ALL = "__all__";

function moduleShort(slug: string, modules: ModuleEntry[]): string {
  const m = modules.find(x => x.slug === slug);
  return m ? (m.short || m.name || slug) : slug;
}

function VerdictChip({ verdict, pct, avgRel }: { verdict?: string; pct?: number | null; avgRel?: number | null }) {
  if (!verdict) return null;
  const label = VERDICT_LABEL[verdict] || verdict;
  const tip = `${pct ?? 0}% caps generic across module's L1 sectors · ${avgRel ?? 0}% avg sector relevance`;
  return (
    <span className={`cm-verdict cm-verdict-${verdict}`} title={tip}>
      {label}
    </span>
  );
}

function SubModuleChipView({ sm }: { sm: SubModuleChip }) {
  return (
    <span
      className={`cm-submod-chip${sm.baseline ? " cm-baseline" : ""}`}
      title={`${sm.module || ""} → ${sm.family || ""}`}
    >
      {sm.canonical_name || sm.id}
      <VerdictChip verdict={sm.verdict} pct={sm.pct_generic ?? null} avgRel={sm.avg_relevance_pct ?? null} />
    </span>
  );
}

export function CoverageMap({
  modules,
  solCats,
  excludedSolCats,
  exclusionGroups,
  submoduleSpecificity: _specificity,
}: Props) {
  const [vertical, setVertical] = useState<string>(ALL);
  const [moduleFilter, setModuleFilter] = useState<string>(ALL);

  const verticals = useMemo(() => {
    const set = new Set<string>();
    for (const sc of solCats) if (sc.vertical) set.add(sc.vertical);
    return Array.from(set).sort();
  }, [solCats]);

  const filtered = useMemo(() => {
    return solCats.filter(sc => {
      if (vertical !== ALL && sc.vertical !== vertical) return false;
      if (moduleFilter !== ALL && !(sc.modules || []).includes(moduleFilter)) return false;
      return true;
    });
  }, [solCats, vertical, moduleFilter]);

  const excludedByGroup = useMemo(() => {
    const out: Record<string, ExcludedSolCat[]> = {};
    for (const sc of excludedSolCats) {
      const g = sc.excluded_group || "unknown";
      (out[g] ||= []).push(sc);
    }
    return out;
  }, [excludedSolCats]);

  return (
    <section className="cm-section">
      <header className="cm-head">
        <h2 className="cm-h2">
          <span className="cm-num">§2</span>
          Coverage map — sol cat → sub-module → cap
        </h2>
        <p className="cm-sub">
          For each PSG sol cat, which ERP modules and which vendor-specialty sub-modules it
          actually touches. <strong>Sub-modules are the qualification unit:</strong> a vendor
          in this sol cat must satisfy at least one sub-module's caps to be considered an
          ERP-grade match. Audit warnings flag sol cats with no IMDA traces (W1) or
          baseline-only mappings (W3). The verdict chip shows whether each sub-module's
          caps are universal or specialty.
        </p>
      </header>

      <div className="cm-legend">
        <span className="cm-legend-eyebrow">Sub-module type:</span>
        <span><span className="cm-verdict cm-verdict-truly_generic">Universal</span> ≥80% caps generic</span>
        <span><span className="cm-verdict cm-verdict-mostly_generic">Common</span> 50-80%</span>
        <span><span className="cm-verdict cm-verdict-mixed">Conditional</span> 20-50%</span>
        <span><span className="cm-verdict cm-verdict-industry_specific">Specialty</span> &lt;20%</span>
      </div>

      <div className="cm-controls">
        <label htmlFor="cm-vert">Vertical</label>
        <select id="cm-vert" value={vertical} onChange={e => setVertical(e.target.value)}>
          <option value={ALL}>All {verticals.length}</option>
          {verticals.map(v => <option key={v} value={v}>{v}</option>)}
        </select>
        <label htmlFor="cm-mod">Module</label>
        <select id="cm-mod" value={moduleFilter} onChange={e => setModuleFilter(e.target.value)}>
          <option value={ALL}>All {modules.length}</option>
          {modules.map(m => <option key={m.slug} value={m.slug}>{m.short || m.name}</option>)}
        </select>
        <span className="cm-count-note">
          {filtered.length} of {solCats.length} sol cats
        </span>
      </div>

      <div className="cm-table">
        <div className="cm-row cm-row-head">
          <div>PSG sol cat</div>
          <div>ERP modules</div>
          <div className="cm-col-num">IMDA Qs</div>
          <div>Sub-modules touched</div>
          <div className="cm-col-warn">Audit</div>
        </div>
        {filtered.length === 0 ? (
          <div className="cm-empty">No sol cats match the current filters.</div>
        ) : (
          filtered.map(sc => (
            <div key={sc.id} className="cm-row">
              <div>
                <div className="cm-name">
                  {sc.display_name || sc.id}
                  {sc.vertical_saas && (
                    <span
                      className="cm-vertical-saas"
                      title={`Vertical mini-ERP — single-app system replacing multiple modules' core for ${sc.vertical_saas_industry || sc.vertical || "this industry"}.`}
                    >
                      vertical mini-ERP
                    </span>
                  )}
                </div>
                <div className="cm-vert">{sc.vertical}</div>
              </div>
              <div>
                {(sc.modules || []).length === 0
                  ? <span className="cm-nope">none</span>
                  : sc.modules.map(slug => (
                      <span key={slug} className="cm-module-chip">{moduleShort(slug, modules)}</span>
                    ))}
              </div>
              <div className="cm-col-num">{sc.imda_req_count ?? 0}</div>
              <div>
                {(sc.sub_modules || []).length === 0
                  ? <span className="cm-nope">— baseline only or unmapped</span>
                  : sc.sub_modules.map(sm => (
                      <SubModuleChipView key={sm.id} sm={sm} />
                    ))}
              </div>
              <div className="cm-col-warn">
                {(sc.warnings || []).map(w => (
                  <span key={w.rule} className={`cm-warn cm-warn-${w.rule}`} title={w.msg || ""}>
                    {w.rule}
                  </span>
                ))}
              </div>
            </div>
          ))
        )}
      </div>

      {excludedSolCats.length > 0 && (
        <details className="cm-excluded">
          <summary>
            Excluded — non-ERP catalogue items ({excludedSolCats.length})
          </summary>
          <p className="cm-excluded-note">
            These sol cats are intentionally out of scope (cybersecurity, utility/AI,
            legal point-tools, BI point-tools). Kept in the catalogue for traceability.
          </p>
          {Object.keys(exclusionGroups).length > 0 && (
            <ul className="cm-exclusion-glossary">
              {Object.entries(exclusionGroups).map(([k, desc]) => (
                <li key={k}>
                  <strong>{EXCLUSION_GROUP_LABEL[k] || k}:</strong> {desc}
                </li>
              ))}
            </ul>
          )}
          {Object.entries(excludedByGroup).map(([g, items]) => (
            <div key={g} className="cm-excluded-group">
              <h4>{EXCLUSION_GROUP_LABEL[g] || g} ({items.length})</h4>
              <div className="cm-excluded-list">
                {items.map(sc => (
                  <div key={sc.id} className="cm-excluded-item">
                    <div className="cm-excluded-name">{sc.display_name || sc.id}</div>
                    <div className="cm-excluded-vert">{sc.vertical}</div>
                    <div className="cm-excluded-reason">{sc.excluded_reason}</div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </details>
      )}
    </section>
  );
}
