import { HashRouter, Route, Routes, useLocation, useParams } from "react-router-dom";
import { useEffect, useState } from "react";
import { api, type Me } from "./lib/api";
import { CanonicalPage } from "./pages/CanonicalPage";
import { StakeholdersPage } from "./pages/StakeholdersPage";
import { HomePage } from "./pages/HomePage";
import { DashboardPage } from "./pages/DashboardPage";
import { DraftsProvider } from "./contexts/DraftsContext";
import { PublishButton } from "./components/PublishButton";
import { NavBar } from "./components/NavBar";

export function App() {
  return (
    <DraftsProvider>
      <HashRouter>
        <Shell />
        <PublishButton />
      </HashRouter>
    </DraftsProvider>
  );
}

function Shell() {
  return (
    <div className="app-shell-spa">
      <ShellHeader />
      <main>
        <Routes>
          <Route path="/" element={<HomePage />} />
          <Route path="/dashboard" element={<DashboardPage />} />
          <Route path="/stakeholders" element={<StakeholdersPage />} />
          <Route path="/canonical/:module" element={<CanonicalPage />} />
        </Routes>
      </main>
    </div>
  );
}

// Active-item resolver for the NavBar. Pulls the current route + (when on
// a canonical page) the module slug so the right item is aria-current=page.
function useActiveNavItem(): "overview" | "stakeholders" | string | undefined {
  const loc = useLocation();
  const params = useParams<{ module?: string }>();
  if (loc.pathname === "/") return "overview";
  if (loc.pathname.startsWith("/dashboard")) return "dashboard";
  if (loc.pathname.startsWith("/stakeholders")) return "stakeholders";
  if (loc.pathname.startsWith("/canonical/") && params.module) return params.module;
  // Try parsing the slug straight from the path so the resolver works
  // outside a route component context (the nav itself isn't a route child).
  const m = loc.pathname.match(/^\/canonical\/([^/]+)/);
  if (m) return m[1];
  return undefined;
}

function ShellHeader() {
  const active = useActiveNavItem();
  const [me, setMe] = useState<Me | null>(null);
  useEffect(() => { api.me().then(setMe).catch(() => {}); }, []);
  return (
    <>
      <NavBar active={active} />
      <div className="app-user-strip">
        {me ? <span className="app-user">{me.email}</span> : <span className="muted">…</span>}
      </div>
    </>
  );
}

