import { useEffect, useState } from "react";
import { loadStakeholdersSummary, type StakeholdersSummary } from "../lib/stakeholdersData";
import { MethodologySection } from "../components/MethodologySection";
import { CoverageMap } from "../components/CoverageMap";
import { EvidenceDrill } from "../components/EvidenceDrill";
import { FulfilmentMatrix } from "../components/FulfilmentMatrix";
import { ErpScoreboard } from "../components/ErpScoreboard";
import { PipelineDeepDive } from "../components/PipelineDeepDive";
import { PerModuleDeepDive } from "../components/PerModuleDeepDive";
import "./StakeholdersPage.css";

type ViewMode = "global" | "per_module";

/**
 * Stakeholders viewer — SPA port of the legacy /stakeholders.html.
 *
 * Sections ship one at a time so each is shippable independently:
 *   §1 Methodology hero + KPI strip + pipeline stages       ← live
 *   §2 Sub-module ↔ sol cat coverage map                    (next)
 *   §3 Evidence drill: cap → sources / module → IMDA Qs     (next)
 *   §4 Sol-cat fulfilment matrix                            (next)
 *   §5 Per-module ERP scoreboard                            (next)
 *   §6 Pipeline deep-dive table + audit cards               (next)
 *   §  Per-module deep-dive sub-view                        (next)
 *
 * Until each section lands here it remains rendered server-side at
 * /stakeholders.html with the full data — that fallback link sits at the
 * bottom of this page so reviewers always have a complete view available.
 */
export function StakeholdersPage() {
  const [summary, setSummary] = useState<StakeholdersSummary | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [mode, setMode] = useState<ViewMode>("global");

  useEffect(() => {
    loadStakeholdersSummary()
      .then(setSummary)
      .catch(e => setError(String(e?.message || e)));
  }, []);

  if (error) {
    return (
      <section className="stakeholders-page error">
        <h1>Stakeholders</h1>
        <p>Failed to load summary: {error}</p>
      </section>
    );
  }

  if (!summary) {
    return (
      <section className="stakeholders-page">
        <p className="muted">Loading stakeholders summary…</p>
      </section>
    );
  }

  return (
    <section className="stakeholders-page">
      <div className="stakeholders-mode-toggle" role="tablist" aria-label="Stakeholders view mode">
        <button
          type="button"
          className={`stakeholders-mode-btn${mode === "global" ? " active" : ""}`}
          aria-pressed={mode === "global"}
          onClick={() => setMode("global")}
        >
          All modules · Methodology
        </button>
        <button
          type="button"
          className={`stakeholders-mode-btn${mode === "per_module" ? " active" : ""}`}
          aria-pressed={mode === "per_module"}
          onClick={() => setMode("per_module")}
        >
          Per-module deep dive
        </button>
      </div>

      {mode === "global" ? (
        <>
          <MethodologySection summary={summary} />

          <CoverageMap
            modules={summary.modules}
            solCats={summary.sol_cats}
            excludedSolCats={summary.excluded_sol_cats}
            exclusionGroups={summary.exclusion_groups}
            submoduleSpecificity={summary.submodule_specificity}
          />

          <EvidenceDrill
            modules={summary.modules}
            caps={summary.caps_index}
            moduleImdaQuestions={summary.module_imda_questions}
            moduleImdaSummary={summary.module_imda_summary}
            proxyIdToName={summary.proxy_id_to_name}
          />

          <FulfilmentMatrix
            modules={summary.modules}
            rows={summary.solcat_fulfilment}
          />

          <ErpScoreboard
            modules={summary.modules}
            caps={summary.caps_index}
            proxyFulfilment={summary.proxy_fulfilment}
            proxyIdToName={summary.proxy_id_to_name}
          />

          <PipelineDeepDive
            stages={summary.pipeline_stages}
            audit={summary.audit_summary}
          />
        </>
      ) : (
        <PerModuleDeepDive
          modules={summary.modules}
          perModuleViews={summary.per_module_views}
          proxyIdToName={summary.proxy_id_to_name}
        />
      )}

      <p className="stakeholders-fallback muted">
        Full server-rendered view also at{" "}
        <a href="/stakeholders.html" className="legacy-link">
          /stakeholders.html
        </a>{" "}
        — same data, kept as a fallback.
      </p>
    </section>
  );
}
